export { PanelResizer } from './components/span-detail-panel';
export { TraceViewerContextProvider, useTraceViewer } from './context';
export * from './trace-viewer';
export type { Trace } from './types';

'use client';

import type { Dispatch, MutableRefObject, ReactNode, Reducer } from 'react';
import {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useReducer,
  useRef,
} from 'react';
import type {
  GetQuickLinks,
  MemoCache,
  MemoCacheKey,
  QuickLink,
  Resource,
  RootNode,
  ScrollSnapshot,
  SpanNode,
  VisibleSpanEvent,
} from './types';
import {
  MAP_HEIGHT,
  MARKER_HEIGHT,
  ROW_HEIGHT,
  ROW_PADDING,
  SEARCH_GAP,
  SEARCH_HEIGHT,
  TIMELINE_PADDING,
} from './util/constants';
import { detectScrollbarWidth } from './util/scrollbar-width';

export interface TraceViewerState {
  /**
   * The root node for the tree
   */
  root: RootNode;
  /**
   * A map of spanId to span nodes
   */
  spanMap: Record<string, SpanNode>;
  /**
   * A map of resource name to resource
   */
  resourceMap: Record<string, Resource['attributes']>;
  /**
   * The current (debounced) search input value
   */
  filter: string;
  /**
   * The span that is currently focused and visible in the panel
   */
  selected: SpanNode | null;
  /**
   * The initial scale of the trace. At this scale the entire trace is visible
   */
  baseScale: number;
  /**
   * The multiplier of the base scale to get the current scale
   */
  scaleRatio: number;
  /**
   * The scale of 1ms in pixels
   */
  scale: number;
  /**
   * The width of the entire trace viewer in pixels
   */
  width: number;
  /**
   * The height of the entire trace viewer in pixels
   */
  height: number;
  /**
   * The width of the timeline view in pixels
   */
  timelineWidth: number;
  /**
   * The height of the timeline view in pixels
   */
  timelineHeight: number;
  /**
   * The width of the side panel in pixels
   */
  panelWidth: number;
  /**
   * The height of the side panel in pixels
   */
  panelHeight: number;
  /**
   * The width of scrollbars on this device
   */
  scrollbarWidth: number;
  /**
   * A ref for the timeline element
   */
  timelineRef: MutableRefObject<HTMLDivElement | null>;
  /**
   * A ref for updating timeline scroll position immediately after a scale operation
   */
  scrollSnapshotRef: MutableRefObject<ScrollSnapshot | undefined>;
  /**
   * A reference for the last time each node was mutated. Used for more efficent control
   * of what React re-renders and when.
   */
  memoCacheRef: MutableRefObject<MemoCache>;
  /**
   * A constant, wrapped version of the getQuickLinks property with caching
   */
  getQuickLinks: GetQuickLinks;
  /**
   * Whether the panel is being rendered attached to the timeline
   */
  withPanel: boolean;
  /**
   * Whether the trace viewer is small enough that it should be in mobile mode
   */
  isMobile: boolean;
  /**
   * A function to provide custom class names for spans.
   */
  customSpanClassNameFunc?: (span: SpanNode) => string;
  /**
   * A function to provide custom class names for span events.
   */
  customSpanEventClassNameFunc?: (event: VisibleSpanEvent) => string;
}

export type TraceViewerAction =
  | {
      type: 'setRoot';
      root: RootNode;
      spanMap: Record<string, SpanNode>;
      resources: Resource[];
    }
  | {
      type: 'setSize';
      width: number;
      height: number;
    }
  | {
      type: 'setPanelWidth';
      width: number;
    }
  | {
      type: 'setFilter';
      filter: string;
    }
  | {
      type: 'deselect';
    }
  | {
      type: 'select';
      id: string;
    }
  | {
      type: 'escape';
    }
  | {
      type: 'toggleSelection';
      id: string;
    }
  | {
      type: 'detectBaseScale';
    }
  | {
      type: 'setScale';
      scale: number;
    }
  | {
      type: 'resetScale';
    }
  | {
      type: 'scaleToNode';
      id: string;
    }
  | {
      type: 'scaleToRange';
      t1: number;
      t2: number;
    }
  | {
      type: 'adjustScaleRatio';
      direction: -1 | 0 | 1;
    }
  | {
      type: 'trackpadScale';
      delta: number;
      anchorT: number;
      anchorX: number;
    }
  | {
      type: 'minScale';
    }
  | {
      type: 'setScrollSnapshot';
      /**
       * The time that will remain the same location after scaling
       */
      anchorT: number;
      /**
       * The anchor point relative to the timeline's left position
       */
      anchorX: number;
    }
  | {
      type: 'setWithPanel';
      withPanel: boolean;
    }
  | {
      type: 'forceRender';
    }
  | {
      /** Like setRoot but preserves scroll position and memo cache (for incremental data updates) */
      type: 'updateRoot';
      root: RootNode;
      spanMap: Record<string, SpanNode>;
      resources: Resource[];
    };

export interface TraceViewerContextProps {
  state: TraceViewerState;
  dispatch: Dispatch<TraceViewerAction>;
}

export const initialState: TraceViewerState = {
  root: {
    startTime: 0,
    endTime: 1,
    duration: 1,
    depth: 0,
    children: [],
  },
  spanMap: {},
  resourceMap: {},
  filter: '',
  selected: null,
  baseScale: 1,
  scaleRatio: 1,
  scale: 1,
  width: 640,
  height: 480,
  timelineWidth: 640,
  timelineHeight: 480,
  panelWidth: 380,
  panelHeight: 480,
  scrollbarWidth: 0,
  timelineRef: { current: null },
  scrollSnapshotRef: { current: undefined },
  memoCacheRef: { current: new Map() },
  getQuickLinks: () => [],
  withPanel: false,
  isMobile: false,
};

const getMinScale = (state: TraceViewerState): number => {
  return (state.timelineWidth - state.scrollbarWidth) / state.root.duration;
};

export const TraceViewerContext = createContext<TraceViewerContextProps>({
  state: initialState,
  dispatch: () => {
    // noop
  },
});
TraceViewerContext.displayName = 'TraceViewerContext';

const reducer: Reducer<TraceViewerState, TraceViewerAction> = (
  state,
  action
) => {
  switch (action.type) {
    case 'setRoot':
      state.scrollSnapshotRef.current = undefined;
      state.memoCacheRef.current.clear();
      return reducer(
        {
          ...state,
          root: action.root,
          spanMap: action.spanMap,
          resourceMap: Object.fromEntries(
            action.resources.map(({ name, attributes }) => [name, attributes])
          ),
        },
        {
          type: 'detectBaseScale',
        }
      );
    case 'setSize': {
      const lowerHeight =
        action.height - MAP_HEIGHT - SEARCH_HEIGHT - 3 * SEARCH_GAP;

      const isMobile = state.withPanel && action.width <= 768;

      let newState = {
        ...state,
        width: action.width,
        height: action.height,
        timelineWidth:
          action.width -
          Number(Boolean(state.selected && state.withPanel && !isMobile)) *
            state.panelWidth,
        timelineHeight: lowerHeight,
        panelHeight: lowerHeight,
        isMobile,
      };

      if (newState.width !== state.width) {
        newState = reducer(newState, {
          type: 'detectBaseScale',
        });
      }

      return newState;
    }
    case 'setPanelWidth': {
      const panelWidth = Math.max(
        240,
        Math.min(action.width, state.width - 240)
      );
      const timelineWidth =
        state.withPanel && state.selected && !state.isMobile
          ? state.width - panelWidth
          : state.width;
      return reducer(
        {
          ...state,
          timelineWidth,
          panelWidth,
        },
        {
          type: 'detectBaseScale',
        }
      );
    }
    case 'setFilter':
      return {
        ...state,
        filter: action.filter,
      };
    case 'deselect':
      return reducer(
        {
          ...state,
          selected: null,
          timelineWidth: state.width,
        },
        {
          type: 'detectBaseScale',
        }
      );
    case 'select': {
      const node = state.spanMap[action.id];
      if (!node) {
        return state;
      }

      return reducer(
        {
          ...state,
          selected: node,
          timelineWidth:
            state.width -
            (state.withPanel && !state.isMobile ? state.panelWidth : 0),
        },
        {
          type: 'detectBaseScale',
        }
      );
    }
    case 'escape': {
      if (state.selected) {
        return reducer(state, {
          type: 'deselect',
        });
      }
      return reducer(state, {
        type: 'resetScale',
      });
    }
    case 'toggleSelection': {
      let newState = state;
      if (state.selected) {
        newState = reducer(newState, {
          type: 'deselect',
        });
      }
      if (state.selected?.span.spanId === action.id) {
        return newState;
      }
      return reducer(newState, {
        type: 'select',
        id: action.id,
      });
    }
    case 'detectBaseScale': {
      const baseScale =
        (state.timelineWidth - state.scrollbarWidth) / state.root.duration;

      return reducer(
        {
          ...state,
          baseScale,
          scale: baseScale * state.scaleRatio,
        },
        {
          type: 'minScale',
        }
      );
    }
    case 'setScale':
      return {
        ...state,
        scaleRatio: action.scale,
        scale: state.baseScale * action.scale,
      };
    case 'resetScale':
      return reducer(state, {
        type: 'scaleToRange',
        t1: state.root.startTime,
        t2: state.root.endTime,
      });
    case 'scaleToNode': {
      const node = state.spanMap[action.id];
      if (!node) {
        return state;
      }
      return reducer(
        reducer(state, {
          type: 'setScale',
          scale:
            (state.width -
              state.scrollbarWidth -
              (state.withPanel && !state.isMobile ? state.panelWidth : 0)) /
            node.duration /
            state.baseScale,
        }),
        {
          type: 'setScrollSnapshot',
          anchorT: node.startTime - state.root.startTime,
          anchorX: 0,
        }
      );
    }
    case 'scaleToRange': {
      const duration = Math.abs(action.t1 - action.t2);

      return reducer(
        reducer(state, {
          type: 'setScale',
          scale:
            (state.width -
              state.scrollbarWidth -
              (state.selected && state.withPanel ? state.panelWidth : 0)) /
            duration /
            state.baseScale,
        }),
        {
          type: 'setScrollSnapshot',
          anchorT: Math.min(action.t1, action.t2) - state.root.startTime,
          anchorX: 0,
        }
      );
    }
    case 'adjustScaleRatio': {
      let { scaleRatio } = state;
      switch (action.direction) {
        case -1:
          scaleRatio *= 0.8;
          break;
        case 1:
          scaleRatio *= 1.25;
          break;
        default:
          scaleRatio = 1;
          break;
      }

      const $timeline = state.timelineRef.current;
      if (!$timeline) {
        console.warn('timelineRef is null');
        return state;
      }

      const { clientWidth, scrollLeft } = $timeline;

      return reducer(
        reducer(
          {
            ...state,
            scaleRatio,
            scale: state.baseScale * scaleRatio,
          },
          {
            type: 'minScale',
          }
        ),
        {
          type: 'setScrollSnapshot',
          anchorT: (scrollLeft + clientWidth * 0.5) / state.scale,
          anchorX: clientWidth * 0.5,
        }
      );
    }
    case 'trackpadScale': {
      const minScaleRatio = getMinScale(state) / state.baseScale;
      const scaleRatio = Math.max(
        minScaleRatio,
        state.scaleRatio *
          (1 +
            0.2 * Math.sign(action.delta) * Math.sqrt(Math.abs(action.delta)))
      );

      return reducer(
        {
          ...state,
          scaleRatio,
          scale: state.baseScale * scaleRatio,
        },
        {
          type: 'setScrollSnapshot',
          anchorT: action.anchorT,
          anchorX: action.anchorX,
        }
      );
    }
    case 'minScale': {
      const minScale = getMinScale(state);
      if (state.scale >= minScale) return state;
      return {
        ...state,
        scale: minScale,
        scaleRatio: minScale / state.baseScale,
      };
    }
    case 'setScrollSnapshot': {
      const $timeline = state.timelineRef.current;
      if (!$timeline) return state;

      const { anchorT, anchorX } = action;

      const scrollLeft = anchorT * state.scale - anchorX;
      const { scrollTop } = $timeline;
      const startRow =
        (scrollTop - MARKER_HEIGHT - TIMELINE_PADDING) /
        (ROW_HEIGHT + ROW_PADDING);
      const endRow =
        startRow + Math.ceil(state.timelineHeight / (ROW_HEIGHT + ROW_PADDING));

      state.scrollSnapshotRef.current = {
        anchorT,
        anchorX,
        scrollLeft,
        scrollTop,
        startTime: state.root.startTime + scrollLeft / state.scale,
        endTime:
          state.root.startTime +
          (scrollLeft + state.timelineWidth) / state.scale,
        startRow,
        endRow,
        scale: state.scale,
      };

      return state;
    }
    case 'setWithPanel': {
      if (state.withPanel === action.withPanel) return state;
      const timelineWidth =
        action.withPanel && state.selected && !state.isMobile
          ? state.width - state.panelWidth
          : state.width;
      return reducer(
        {
          ...state,
          withPanel: action.withPanel,
          timelineWidth,
        },
        {
          type: 'detectBaseScale',
        }
      );
    }
    case 'forceRender':
      state.memoCacheRef.current.set('', {});
      return {
        ...state,
      };
    case 'updateRoot':
      // Incremental update: preserve scroll snapshot and only invalidate
      // memo cache for spans whose data may have changed
      state.memoCacheRef.current.set('', {});
      return reducer(
        {
          ...state,
          root: action.root,
          spanMap: action.spanMap,
          resourceMap: Object.fromEntries(
            action.resources.map(({ name, attributes }) => [name, attributes])
          ),
        },
        {
          type: 'detectBaseScale',
        }
      );
  }
};

export function TraceViewerContextProvider({
  getQuickLinks,
  withPanel = false,
  children,
  customSpanClassNameFunc,
  customSpanEventClassNameFunc,
  customPanelComponent = null,
}: {
  getQuickLinks?: GetQuickLinks;
  withPanel?: boolean;
  children: ReactNode;
  customSpanClassNameFunc?: (span: SpanNode) => string;
  customSpanEventClassNameFunc?: (event: VisibleSpanEvent) => string;
  customPanelComponent?: ReactNode;
}): ReactNode {
  const timelineRef = useRef<HTMLDivElement>(null);
  const scrollSnapshotRef = useRef<ScrollSnapshot>(undefined);
  const getQuickLinksRef = useRef(getQuickLinks);
  getQuickLinksRef.current = getQuickLinks;
  const memoCacheRef = useRef(new Map<string, MemoCacheKey>());
  const quickLinksCache = useRef(new Map<string, QuickLink[]>());
  const [state, dispatch] = useReducer(reducer, initialState, (initial) => {
    return {
      ...initial,
      scrollbarWidth: detectScrollbarWidth(),
      timelineRef,
      scrollSnapshotRef,
      customSpanClassNameFunc,
      customSpanEventClassNameFunc,
      memoCacheRef,
      withPanel,
      getQuickLinks: (span) => {
        const cacheKey = span.spanId;
        const existing = quickLinksCache.current.get(cacheKey);
        if (existing) return existing;

        const value = getQuickLinksRef.current?.(span) || [];
        quickLinksCache.current.set(cacheKey, value);
        return value;
      },
    };
  });

  useEffect(
    () =>
      dispatch({
        type: 'setWithPanel',
        withPanel,
      }),
    [withPanel]
  );

  const value: TraceViewerContextProps = useMemo(
    () => ({ state, dispatch }),
    [state, dispatch]
  );

  return (
    <CustomPanelContext.Provider value={customPanelComponent}>
      <TraceViewerContext.Provider value={value}>
        {children}
      </TraceViewerContext.Provider>
    </CustomPanelContext.Provider>
  );
}

export const useTraceViewer = (): TraceViewerContextProps =>
  useContext(TraceViewerContext);

/**
 * Separate context for the custom panel component. This is intentionally
 * outside the useReducer state so that the panel re-renders reactively
 * when props like spanDetailData change.
 */
const CustomPanelContext = createContext<ReactNode | null>(null);

export const useCustomPanelComponent = (): ReactNode | null =>
  useContext(CustomPanelContext);

import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

const durationFormatter = new Intl.NumberFormat(undefined, {
  maximumFractionDigits: 2,
})

const MS_IN_SECOND = 1000
const MS_IN_MINUTE = 60 * MS_IN_SECOND
const MS_IN_HOUR = 60 * MS_IN_MINUTE
const MS_IN_DAY = 24 * MS_IN_HOUR

export function formatDuration(ms: number, compact = false): string {
  if (ms === 0) {
    return "0"
  }

  if (ms < MS_IN_SECOND) {
    return `${durationFormatter.format(ms)}ms`
  }

  if (ms < MS_IN_MINUTE) {
    return `${durationFormatter.format(ms / MS_IN_SECOND)}s`
  }

  if (compact) {
    if (ms < MS_IN_HOUR) {
      return `${durationFormatter.format(ms / MS_IN_MINUTE)}m`
    }

    return `${durationFormatter.format(ms / MS_IN_HOUR)}h`
  }

  const days = Math.floor(ms / MS_IN_DAY)
  const hours = Math.floor((ms % MS_IN_DAY) / MS_IN_HOUR)
  const minutes = Math.floor((ms % MS_IN_HOUR) / MS_IN_MINUTE)
  const seconds = Math.floor((ms % MS_IN_MINUTE) / MS_IN_SECOND)
  const parts: string[] = []

  if (days > 0) {
    parts.push(`${days}d`)
  }

  if (hours > 0) {
    parts.push(`${hours}h`)
  }

  if (minutes > 0) {
    parts.push(`${minutes}m`)
  }

  if (hours <= 1 && (seconds > 0 || parts.length === 0)) {
    parts.push(`${seconds}s`)
  }

  return parts.join(" ")
}

/**
 * Required for CSS modules to be supported by TypeScript.
 * https://github.com/mrmckeb/typescript-plugin-css-modules#custom-definitions
 */

declare module '*.module.css' {
  const classes: Record<string, string>;

  export default classes;
}

declare module '*.svg' {
  const content: { src: string };

  export default content;
}

.traceNode {
  position: relative;
}

.childRow {
  display: flex;
  flex-direction: row;
  align-items: flex-start;
}

.spanNode {
  position: absolute;
  display: flex;
  flex-direction: row;
  align-items: center;
  padding: 0;
  background-color: var(--span-background);
  color: var(--span-text);
  border: 1px solid var(--span-border);
  border-radius: 8px;
  text-overflow: ellipsis;
  white-space: nowrap;
  box-shadow: var(--ds-shadow-small);
  overflow: hidden;
  text-overflow: ellipsis;
  content-visibility: auto;
  cursor: pointer;
  user-select: none;
  z-index: 2;

  &.huge {
    overflow: visible;

    & .spanName {
      flex: 0 1 auto;
      position: sticky;
      left: 0;
    }

    & .spanSpacer {
      flex: 1 0 0;
    }

    & .spanDuration {
      position: sticky;
      right: 0;
      background-color: var(--span-background);
      padding-left: 6px;
      box-shadow: -8px 0 16px 8px var(--span-background);
    }
  }

  &::after {
    position: absolute;
    left: -1px;
    top: -1px;
    width: var(--span-width);
    height: var(--row-height);
    content: "";
  }

  &.small:not(.xHover)::after {
    top: -7px;
  }

  &:hover:not([data-selected]) {
    filter: brightness(0.95);
  }

  &.xHover {
    z-index: 3;
    min-width: var(--span-width);
    max-width: 75%;
    background: linear-gradient(
      90deg,
      var(--span-background) calc(var(--span-width) - 1px),
      var(--span-line),
      var(--geist-background) calc(var(--span-width) + 1px)
    );

    &[data-right-side="true"] {
      background: linear-gradient(
        270deg,
        var(--span-background) calc(var(--span-width) - 1px),
        var(--span-line),
        var(--geist-background) calc(var(--span-width) + 1px)
      );
    }

    & .spanName {
      max-width: max(var(--span-width), 40vw);
    }

    & .spanDuration {
      background: none;
      box-shadow: none;
    }
  }

  &.small:not(.xHover) {
    background-color: var(--span-background);
    border-color: var(--span-border);
    border-radius: 4px;
  }

  &[data-selected] {
    border-width: 2px;
    outline: 2px solid var(--span-border);
    outline-offset: -1px;

    &:hover {
      filter: brightness(0.95);
    }
  }

}

.spanNodeEvent {
  position: absolute;
  height: var(--row-height);
  pointer-events: none;
  z-index: 4;

  & .eventDiamond {
    --size: 7px;
    --offset: -4px;
    position: absolute;
    left: var(--offset);
    bottom: calc(var(--offset) + 1px);
    width: var(--size);
    height: var(--size);
    border: 1px solid var(--span-secondary);
    border-radius: 2px;
    background: var(--span-background);
    transform-origin: 50% 50% 0;
    transform: rotate(45deg);
  }

  /* Workflow-specific: Use custom event color if provided */
  &.customEventColor .eventDiamond {
    border-color: var(--event-color, var(--span-border));
    background: var(--event-color, var(--span-background));
    opacity: 0.8;
  }
  &.customEventColor .hoverInfo {
    border-color: var(--span-border);
    background: var(--span-background);
  }
  &.customEventColor .hoverInfo .eventName {
    color: var(--span-text);
    font-weight: 500;
  }
  &.customEventColor .hoverInfo .eventTimestamp {
    color: var(--span-secondary);
  }

  & .hoverInfo {
    position: absolute;
    margin-top: -1px;
    top: 100%;
    display: none;
    flex-direction: row;
    align-items: center;
    gap: 6px;
    padding: 3px 6px;
    font-size: 12px;
    line-height: 1;
    background: var(--span-background);
    border: 1px solid var(--span-border);
    border-radius: 6px;
    box-shadow: var(--ds-shadow-small);
    transform: translateY(-50%);

    &.alignStart {
      left: -10px;
      padding-left: 18px;
    }
    &.alignEnd {
      right: -10px;
      padding-right: 18px;
    }

    & .eventName {
      color: var(--span-text);
    }
    & .eventTimestamp {
      color: var(--span-secondary);
      font-variant-numeric: tabular-nums;
    }
  }

  &[data-hovered="true"] {
    z-index: 4;

    & .eventDiamond {
      background: var(--span-text);
      border-color: var(--span-text);
    }
    & .hoverInfo {
      display: flex;
    }
  }
}

.colorVercel {
  --span-background: var(--ds-background-100);
  --span-border: var(--ds-gray-500);
  --span-line: var(--ds-gray-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-gray-900);
  --geist-background: var(--ds-gray-100);
}
.color0 {
  --span-background: var(--ds-teal-200);
  --span-border: var(--ds-teal-500);
  --span-line: var(--ds-teal-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-teal-900);
}
.color1 {
  --span-background: var(--ds-blue-200);
  --span-border: var(--ds-blue-500);
  --span-line: var(--ds-blue-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-blue-900);
}
.color2 {
  --span-background: var(--ds-green-200);
  --span-border: var(--ds-green-500);
  --span-line: var(--ds-green-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-green-900);
}
.color3 {
  --span-background: var(--ds-purple-200);
  --span-border: var(--ds-purple-500);
  --span-line: var(--ds-purple-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-purple-900);
}
.color4 {
  --span-background: var(--ds-pink-200);
  --span-border: var(--ds-pink-500);
  --span-line: var(--ds-pink-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-pink-900);
}
.colorHighlight {
  --span-background: var(--ds-amber-200);
  --span-border: var(--ds-amber-500);
  --span-line: var(--ds-amber-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-amber-900);
}

.unlit {
  opacity: 0.3;
}

:global(.dark-theme),
:global(.dark) {
  & .mapContainer canvas {
    filter: invert(1);
  }

  & .spanNode.small {
    &.xHover,
    &:focus-visible {
      &::before {
        text-shadow: 0 1px 0 black;
      }
    }
  }

  & .spanNode:hover:not([data-selected]) {
    filter: brightness(1.05);
  }

  & .spanNode[data-selected]:hover {
    filter: brightness(1.05);
  }
}

@media (prefers-color-scheme: dark) {
  :global(:root:not(.light)) {
    & .mapContainer canvas {
      filter: invert(1);
    }

    & .spanNode.small {
      &.xHover,
      &:focus-visible {
        &::before {
          text-shadow: 0 1px 0 black;
        }
      }
    }

    & .spanNode:hover:not([data-selected]) {
      filter: brightness(1.05);
    }

    & .spanNode[data-selected]:hover {
      filter: brightness(1.05);
    }
  }
}

.spanName {
  flex: 1 1 auto;
  padding-inline: 6px;
  text-align: left;
  overflow: hidden;
  text-overflow: ellipsis;
  position: relative;
  z-index: 1;
}

.spanDuration {
  flex: 0 0 auto;
  padding-right: 6px;
  font-variant-numeric: tabular-nums;
  color: var(--span-secondary, var(--ds-gray-alpha-700));
  position: relative;
  z-index: 1;
}

/* SPAN DETAIL PANEL */
.spanDetailPanel {
  display: flex;
  flex-direction: column;
  height: 100%;
  align-items: stretch;
  justify-content: flex-start;
  flex: 0 1 auto;
}

.spanDetailPanelResizer {
  position: absolute;
  left: 0;
  top: 0;
  width: 20px;
  height: 100%;
  cursor: col-resize;
  z-index: 1;

  display: none;
  @media (hover: hover) {
    display: block;
  }
}

.spanDetailPanelTop {
  display: flex;
  flex-direction: row;
  align-items: stretch;
  flex: 0 1 auto;
  justify-content: space-between;
  position: relative;
}

.spanDetailPanelBody {
  display: flex;
  flex-direction: column;
  align-items: stretch;
  justify-content: flex-start;
  gap: 12px;
  flex: 1 1 0;
  min-height: 0;
  padding: 16px 12px 24px;
  overflow-x: hidden;
  overflow-y: auto;
}

.spanDetailPanelTopInfo {
  --row-height: 32px;
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  padding: 8px 12px;
  width: 100%;
  font-size: 12px;
  border-bottom: 1px solid var(--border-color);
  flex: 0 1 auto;
}

.spanNameDetailPanel {
  font-size: inherit;
  color: var(--ds-gray-1000);
  word-break: break-word;
}

.spanDetailPanelTruncatedHeading {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 8px;
  flex: 0 1 100%;
  overflow: hidden;
  justify-content: flex-start;
}

.spanDetailPanelName {
  flex: 1 1 0;
  font-size: 12px;
  font-weight: 500;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--ds-gray-1000);
}

.spanDetailPanelDuration {
  font-family: var(--font-mono);
  font-size: 10px;
  font-variant-numeric: tabular-nums;
  color: var(--ds-gray-600);
  background-color: var(--ds-gray-200);
  padding: 2px 6px;
  border-radius: 4px;
  flex-shrink: 0;
}

.spanDetailPanelCorner {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 8px;
  flex: 0 0 auto;
  height: var(--row-height);
  justify-content: flex-end;
}

.spanDetailPanelCornerInner {
  display: flex;
  flex-direction: row;
  align-items: stretch;
  justify-content: flex-start;
  flex: 0 1 auto;
}

.spanDetailPanelCloseVerticalRule {
  border-left: 1px solid var(--ds-gray-300);
  height: 16px;
}

.spanDetailPanelClose {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  background: none;
  border: none;
  border-radius: 4px;
  cursor: pointer;

  &:hover,
  &:focus-visible {
    background-color: var(--ds-gray-200);
  }
}

.spanDetailPanelAttribute {
  margin: 0;
  padding-block: 8px;
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  font-size: 14px;
  line-height: 1.4;
  border-bottom: 1px solid var(--border-color);

  &:last-child {
    border-bottom: none;
  }
}

.spanDetailPanelAttributeKey {
  flex: 0 0 auto;
  margin: 0;
  padding-left: 8px;
  font-size: inherit;
  color: var(--ds-gray-900);
}

.spanDetailPanelAttributeValue {
  flex: 0 1 auto;
  margin: 0;
  padding-right: 8px;
  font-family: var(--font-mono);
  font-size: 13px;
  white-space: nowrap;
  overflow-x: hidden;
  text-overflow: ellipsis;
}

.spanDetailPanelQuickLink {
  color: inherit;
  text-decoration: none;
  &:hover .spanDetailPanelQuickLinkLabel {
    text-decoration: underline;
  }
}

.spanDetailPanelQuickLinkLabel {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 8px;
  font: inherit;
}

.detailGroup {
  display: flex;
  flex-direction: column;
  align-items: stretch;
  justify-content: flex-start;
  flex: 0 1 auto;
  &::after {
    margin: 12px -12px 0;
    height: 1px;
    background: var(--border-color);
    content: "";
  }
}

.expanded,
.collapsed,
.ancestorGroup {
  /* Explicit class tokens used by TS for CSS Modules */
}

.detailHeading {
  display: flex;
  flex-direction: row;
  justify-content: space-between;
  align-items: center;
  padding: 8px;
  font-family: inherit;
  font-size: 14px;
  font-weight: 500;
  background: none;
  color: var(--ds-gray-1000);
  border: none;
  border-radius: 6px;
  cursor: pointer;
  -webkit-tap-highlight-color: transparent;

  &:hover,
  &:focus-visible {
    background-color: var(--ds-gray-100);
  }
}

/* Local replacements for external UI */
.buttonLink {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 4px 8px;
  font-size: 12px;
  line-height: 1;
  color: var(--ds-gray-1000);
  text-decoration: none;
  background-color: var(--ds-background-100);
  border: 1px solid var(--accents-2);
  border-radius: 6px;
}

.buttonLink:hover,
.buttonLink:focus-visible {
  background-color: var(--ds-gray-100);
}

.note {
  padding: 8px 10px;
  color: var(--ds-gray-900);
  background-color: var(--ds-background-100);
  border: 1px solid var(--ds-gray-300);
  border-radius: 6px;
}

.skeleton {
  display: inline-block;
  background-color: var(--ds-gray-200);
  border-radius: 4px;
}

.skeletonRounded {
  border-radius: 50%;
}

.detailGroup.collapsed .detailHeadingIcon {
  transform: rotate(-90deg);
}

.infraSpanDescription {
  padding: 8px;
  font-size: 14px;
  line-height: 1.4;
  color: var(--ds-gray-900);
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.ancestorNode {
  padding: 8px 8px 8px;
  font-family: inherit;
  font-size: 13px;
  background: none;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  -webkit-tap-highlight-color: transparent;

  &:hover,
  &:focus-visible {
    background: var(--ds-gray-100);
  }
}

.ancestorText {
  display: flex;
  flex-direction: row;
  justify-content: space-between;
  align-items: center;
  gap: 4px;
  color: var(--ds-gray-900);
  white-space: nowrap;
}

.ancestorName {
  overflow: hidden;
  text-overflow: ellipsis;
}

.ancestorDuration {
  /* font-family: var(--font-mono); */
  font-variant-numeric: tabular-nums;
}

.ancestorLineContainer {
  position: relative;
  margin-top: 6px;
  display: block;
  width: 100%;
  height: 1px;
  background-color: var(--ds-gray-alpha-400);

  &::before,
  &::after {
    position: absolute;
    top: -2px;
    width: 1px;
    height: 5px;
    background-color: inherit;
    content: "";
  }

  &::before {
    left: 0;
  }

  &::after {
    right: 0;
  }
}

.ancestorLine {
  position: absolute;
  top: -2px;
  height: 5px;
  background-color: var(--span-background);
  border: 1px solid var(--span-line);
  border-radius: 1px;
}

.ancestorNode {
  &:hover,
  &:focus-visible,
  &:last-of-type {
    & .ancestorName {
      color: var(--ds-gray-1000);
    }

    & .ancestorLine {
      background-color: var(--span-line);
      border-color: var(--span-border);
    }
  }
}

/* ZOOM BUTTON */
.zoomButtonGroup {
  display: inline-flex;
  flex-direction: row;
  align-items: stretch;
  justify-content: flex-start;
  flex: 0 1 auto;
  background-color: var(--geist-background);
  border-radius: 10ex;
  box-shadow: var(--ds-shadow-small);
  border: 1px solid var(--accents-2);
  animation: zoom-buttons-fade-in 0.3s ease 0.3s backwards;
}

@keyframes zoom-buttons-fade-in {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

.zoomButton {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 6px;
  height: 32px;
  width: 38px;
  background-color: transparent;
  border: none;
  color: var(--accents-5);
  box-shadow: none !important;
  cursor: pointer;

  &:hover,
  &:focus-visible {
    color: var(--accents-7);
  }
}

.zoomButton:hover {
  background-color: transparent;
  color: var(--accents-7);
}

.zoomButton:focus-visible {
  /* TODO */
}

.divider {
  width: 1px;
  background-color: var(--accents-2);
  margin: -1px;
}

/* TRACE */
.markersContainer {
  position: absolute;
  left: -8px;
  top: -8px;
  width: 100%;
  height: calc(100% - var(--scrollbar-width));
  line-height: 1;
  z-index: 4;
  pointer-events: none;
}

.markers {
  position: sticky;
  top: 0;
  display: flex;
  flex-direction: row;
  gap: calc(var(--marker-width) - 1px);
  height: var(--marker-height);
  padding-left: 8px;
  background: var(--ds-background-200);
  overflow: hidden;
  box-shadow: 0 4px 8px 0 var(--ds-background-200);
  border-bottom: 1px solid var(--marker-color);
}

.marker {
  position: relative;
  flex: 0 0 1px;
  border-left: 1px solid var(--marker-color);
  font-size: 10px;
  font-variant-numeric: tabular-nums;
  color: var(--ds-gray-900);

  height: var(--marker-height);
  &.notch {
    top: calc(var(--marker-height) - var(--marker-notch-height));
    height: var(--marker-notch-height);
  }
}

.markerLabel {
  position: absolute;
  left: 2px;
  bottom: 6px;
  color: var(--ds-gray-900);
  user-select: none;
  white-space: nowrap;
}

.markerClockTime {
  display: block;
  font-size: 9px;
  color: var(--ds-gray-alpha-500);
  margin-top: 1px;
  letter-spacing: 0.02em;
  white-space: nowrap;
}

.eventMarkersContainer {
  position: absolute;
  top: -8px;
  width: var(--timeline-scroll-width);
  height: calc(100% - var(--scrollbar-width));
  line-height: 1;
  z-index: 1;
  pointer-events: none;
}

.eventMarkers {
  position: sticky;
  top: 0;
  height: calc(100% + 2 * var(--timeline-padding));
  overflow: hidden;
}

.eventMarker {
  position: absolute;
  border-left: 1px dotted var(--ds-gray-500);
  height: 100%;
}

.cursorMarkerStickyParent {
  position: absolute;
  left: 0;
  top: -8px;
  width: var(--timeline-scroll-width);
  height: calc(100% + 2 * var(--timeline-padding));
  pointer-events: none;
}

.cursorMarkerLabelContainer {
  position: sticky;
  top: 0;
  left: 0;
  display: none;
  width: 1px;
  height: 100%;
  z-index: 5;
  pointer-events: none;
}

.cursorMarkerLabel {
  position: sticky;
  top: 4px;
  width: 1px;
  height: var(--marker-height);
  background-color: var(--marker-color);

  &[data-text]::before {
    margin: 0;
    position: absolute;
    left: 0;
    top: 0;
    padding: 0 6px;
    height: 18px;
    line-height: 16px;
    transform: translateX(-50%);
    font-size: 10px;
    font-weight: 500;
    font-variant-numeric: tabular-nums;
    background-color: var(--ds-background-100);
    color: var(--ds-gray-900);
    border: 1px solid var(--ds-gray-500);
    border-radius: 10ex;
    box-shadow: var(--ds-shadow-small);
    content: attr(data-text);
  }

  &[data-align="left"]::before {
    left: -6px;
    transform: unset;
  }

  &[data-align="right"]::before {
    left: unset;
    right: -6px;
    transform: unset;
  }
}

.cursorMarkerContainer {
  position: sticky;
  top: 0;
  width: 1px;
  height: 100%;
  pointer-events: none;
}

.cursorMarker {
  position: sticky;
  top: 0;
  width: 1px;
  height: 100%;
  display: none;
  background-color: var(--marker-color);
  z-index: 1;
}

.cursorSelection {
  position: absolute;
  top: 0;
  height: 100%;
  display: none;
  flex-direction: row;
  justify-content: space-between;
  align-items: flex-end;
  gap: 8px;
  background-color: var(--ds-gray-100);
  border-inline: 1px solid var(--ds-gray-300);

  &::before,
  &::after {
    position: sticky;
    bottom: 8px;
    padding: 0 6px;
    height: 18px;
    line-height: 16px;
    font-size: 10px;
    font-weight: 500;
    font-variant-numeric: tabular-nums;
    background-color: var(--ds-background-100);
    color: var(--ds-gray-900);
    border: 1px solid var(--ds-gray-500);
    border-radius: 10ex;
    box-shadow: var(--ds-shadow-small);
    white-space: nowrap;
  }

  &::before {
    margin-left: 8px;
    content: attr(data-range);
  }
  &::after {
    margin-right: 8px;
    content: attr(data-duration);
  }
}

@keyframes span-skeleton {
  from {
    opacity: 0.6;
  }

  to {
    opacity: 0.3;
  }
}

.traceViewer {
  &.skeleton {
    & * {
      pointer-events: none !important;
    }

    & .mapCanvas {
      display: none;
    }

    & .markerLabel {
      display: none;
    }

    & .spanNode {
      animation: span-skeleton 1s infinite alternate;

      & * {
        display: none;
      }
    }

    & .zoomButtonTraceViewer {
      display: none;
    }
  }

  & .markers {
    border-top: 1px solid var(--marker-color);
    border-bottom: none;
  }

  & .marker.notch {
    top: 0;
  }

  & .markerLabel {
    bottom: 3px;
  }

  & .cursorMarkerLabel {
    top: 8px;
  }
}

.timeline:hover {
  & .cursorMarkerLabelContainer,
  & .cursorMarker {
    display: block;
  }
}

/* SEARCH BAR */
.searchBar {
  position: absolute;
  left: 0;
  top: var(--search-gap);
  display: flex;
  flex-direction: row;
  gap: var(--search-gap);
  width: 100%;
  padding-inline: var(--search-gap);
  height: var(--search-height);
}

.searchInput {
  flex: 0 1 100%;
  position: relative;
  height: var(--search-height);
  background: var(--ds-background-100);
}

.searchInputLabel {
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 6px;
  box-shadow: 0 0 0 1px var(--border-color, var(--ds-gray-alpha-400));

  & input {
    margin-left: -16px;
    padding-inline: 12px;
    font-family: inherit;
    font-size: 14px;
    background: transparent;
    border: none;
    outline: none;

    &::-webkit-search-decoration,
    &::-webkit-search-cancel-button,
    &::-webkit-search-results-button,
    &::-webkit-search-results-decoration {
      display: none;
    }
  }
}

.searchInputPrefix {
  width: var(--search-height);
  height: var(--search-height);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--ds-gray-800);
}

/* MINI MAP */
.mapContainer {
  position: absolute;
  left: 0;
  top: calc(var(--search-height) + 2 * var(--search-gap));
  /* border-bottom: 1px solid var(--border-color); */
  cursor: move;
}

.mapCanvas {
  position: absolute;
  left: 0;
  top: 0;
  z-index: 1;
  pointer-events: none;
  mix-blend-mode: multiply;
}

:global(.dark-theme) .mapCanvas,
:global(.dark) .mapCanvas {
  mix-blend-mode: screen;
}

@media (prefers-color-scheme: dark) {
  :global(:root:not(.light)) .mapCanvas {
    mix-blend-mode: screen;
  }
}

.mapThumb {
  position: absolute;
  top: 0;
  height: var(--map-height);
  background: var(--ds-gray-alpha-200);
  border: 1px solid var(--ds-gray-alpha-400);
  border-radius: 3px;
  box-shadow: var(--ds-shadow-small);
  transform: translateX(var(--timeline-padding));
  pointer-events: none;
}

/* TRACE VIEWER */
.traceViewer,
.spanDetailPanelTraceViewer {
  --border-color: var(--ds-gray-300);
  --marker-color: var(--ds-gray-300);
}

.traceViewer {
  --scrollbar-width: 0;
  position: relative;
  display: flex;
  font-family: var(--font-sans);
  text-rendering: optimizeLegibility;
  text-size-adjust: 100%;
  background-color: var(--ds-background-200);

  & button {
    font-family: inherit;
  }
}

.traceViewerContent {
  position: absolute;
  left: 0;
  top: calc(var(--search-height) + 3 * var(--search-gap) + var(--map-height));
  width: calc(var(--timeline-width) + 2 * var(--timeline-padding));
  height: calc(
    var(--timeline-height) - 2 * var(--timeline-padding) -
      var(--scrollbar-width) - var(--marker-height) - var(--search-height)
  );

  &.inert {
    display: none;
  }
}

.timeline {
  width: calc(var(--timeline-width) + 2 * var(--timeline-padding));
  height: var(--timeline-height);
  font-size: 13px;
  overflow-y: scroll;
  overflow-x: scroll;
  -webkit-overflow-scrolling: touch;
  position: relative;
}

.zoomButtonTraceViewer {
  position: absolute;
  bottom: calc(-12px - var(--search-height) - var(--scrollbar-width));
  right: calc(var(--scrollbar-width) + 12px);
  z-index: 10;
}

.spanDetailPanelTraceViewer {
  position: absolute;
  margin-top: -1px;
  right: 0;
  top: calc(
    var(--search-height) + 2 * var(--search-gap) + var(--map-height) + 9px
  );
  bottom: 0;
  width: var(--panel-width);
  border-top: 1px solid var(--ds-gray-200);
  border-left: 1px solid var(--ds-gray-200);
  background-color: var(--geist-background);
  z-index: 10;

  &.hidden {
    display: none;
  }

  &.mobile {
    --panel-width: calc(var(--timeline-width) + 2 * var(--timeline-padding));
    top: 0;
    border-left: none;
  }
}

/* Workflow-specific styles */

/* Step statuses */
.spanRunning,
.spanPending {
  --span-background: var(--ds-blue-200);
  --span-border: var(--ds-blue-500);
  --span-line: var(--ds-blue-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-blue-900);
}

.spanCompleted {
  --span-background: var(--ds-green-200);
  --span-border: var(--ds-green-500);
  --span-line: var(--ds-green-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-green-900);
}

.spanCancelled {
  --span-background: var(--ds-amber-200);
  --span-border: var(--ds-amber-500);
  --span-line: var(--ds-amber-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-amber-900);
}

.spanFailed {
  --span-background: var(--ds-red-200);
  --span-border: var(--ds-red-500);
  --span-line: var(--ds-red-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-red-900);
}

/* Striped background for pending status */
.spanPendingStriped {
  --span-background: repeating-linear-gradient(
    45deg,
    var(--ds-blue-200),
    var(--ds-blue-200) 10px,
    color-mix(in srgb, var(--ds-blue-200) 70%, white) 10px,
    color-mix(in srgb, var(--ds-blue-200) 70%, white) 20px
  );
  --span-border: var(--ds-blue-500);
  --span-line: var(--ds-blue-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-blue-900);
}

.hasQueuedTime {
  &::before {
    content: "";
    position: absolute;
    left: var(--queued-width);
    height: 100%;
    border-left: 2px dotted var(--ds-gray-700);
    pointer-events: none;
  }
}

/* Sleep step - light yellow/orange */
.spanSleep {
  --span-background: var(--ds-amber-200);
  --span-border: var(--ds-amber-500);
  --span-line: var(--ds-amber-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-amber-900);
}

/* Hooks - gray color scheme */
.spanHook {
  --span-background: var(--ds-gray-200);
  --span-border: var(--ds-gray-500);
  --span-line: var(--ds-gray-400);
  --span-text: var(--ds-gray-1000);
  --span-secondary: var(--ds-gray-900);
}

/* ──────────────────────────────────────────────────────────────────────── */
/* Span segments — colored sections overlaid inside span bars              */
/* ──────────────────────────────────────────────────────────────────────── */

.segmentLayer {
  position: absolute;
  inset: 0;
  z-index: 0;
  border-radius: inherit;
  pointer-events: none;
}

.segment {
  position: absolute;
  top: 0;
  bottom: 0;
  pointer-events: auto;
  overflow: hidden;
}

.segmentLabel {
  display: flex;
  align-items: center;
  height: 100%;
  padding: 0 4px;
  font-size: 9px;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
  color: var(--ds-gray-900);
  opacity: 0.7;
  pointer-events: none;
  user-select: none;
}

/* Inline segment tags rendered next to the span name */
.segmentTag {
  font-size: 10px;
  font-variant-numeric: tabular-nums;
  opacity: 0.6;
  white-space: nowrap;
}

/* Queued: hatched — waiting to start */
.segQueued {
  background: repeating-linear-gradient(
    45deg,
    var(--ds-gray-alpha-200),
    var(--ds-gray-alpha-200) 6px,
    var(--ds-gray-alpha-100) 6px,
    var(--ds-gray-alpha-100) 12px
  );
}

/* Running: soft blue — actively executing */
.segRunning {
  background-color: var(--ds-blue-200);
}

/* Failed: soft red — attempt ended in failure */
.segFailed {
  background-color: var(--ds-red-200);
}

/* Retrying: hatched — waiting between retry attempts */
.segRetrying {
  background: repeating-linear-gradient(
    45deg,
    var(--ds-gray-alpha-200),
    var(--ds-gray-alpha-200) 6px,
    var(--ds-gray-alpha-100) 6px,
    var(--ds-gray-alpha-100) 12px
  );
}

/* Succeeded: soft green — final successful attempt */
.segSucceeded {
  background-color: var(--ds-green-200);
}

/* Waiting: hatched — hook waiting for payload */
.segWaiting {
  background: repeating-linear-gradient(
    45deg,
    var(--ds-gray-alpha-200),
    var(--ds-gray-alpha-200) 6px,
    var(--ds-gray-alpha-100) 6px,
    var(--ds-gray-alpha-100) 12px
  );
}

/* Sleeping: soft amber — sleep in progress */
.segSleeping {
  background-color: var(--ds-amber-200);
}

/* Received: soft blue — hook received payload */
.segReceived {
  background-color: var(--ds-blue-200);
}

/* Boundary markers — workflow events shown as thin vertical lines instead of diamonds */
.boundaryMarker {
  & .boundaryLine {
    position: absolute;
    left: -0.5px;
    top: 0;
    bottom: 0;
    width: 1px;
    background-color: transparent;
    z-index: 0;
    transition: background-color 0.15s ease;
  }

  &[data-hovered="true"] .boundaryLine {
    background-color: var(--ds-gray-alpha-400);
  }

  /* Tooltip must sit above the boundary line */
  & .hoverInfo {
    z-index: 1;
  }
}

/* When segments are active, make span background transparent so segments show */
.spanNode.hasSegments {
  background-color: transparent;

  &.small:not(.xHover) {
    background-color: transparent;
  }

  /* Suppress hover expansion gradient — segments handle the background */
  &.xHover {
    background: none;
    min-width: var(--span-width);
    max-width: var(--span-width);

    &[data-right-side="true"] {
      background: none;
    }
  }

  /* Remove duration label background bleed — segments provide the visual */
  & .spanDuration {
    background-color: transparent;
    box-shadow: none;
  }

  /* Let segment tooltips receive pointer events */
  &::after {
    pointer-events: none;
  }

  & .segmentLayer {
    pointer-events: auto;
  }
}

/* Event markers */

/* Failure events - Red */
.eventFailed {
  --event-color: var(--ds-red-600);
  --span-background: var(--ds-red-100);
  --span-border: var(--ds-red-500);
  --span-text: var(--ds-red-900);
  --span-secondary: var(--ds-red-700);
}

/* Retry events - Orange/Yellow */
.eventRetrying {
  --event-color: var(--ds-amber-600);
  --span-background: var(--ds-amber-100);
  --span-border: var(--ds-amber-500);
  --span-text: var(--ds-amber-900);
  --span-secondary: var(--ds-amber-700);
}

/* Webhook-related events - Purple */
.eventHook {
  --event-color: var(--ds-purple-600);
  --span-background: var(--ds-purple-100);
  --span-border: var(--ds-purple-500);
  --span-text: var(--ds-purple-900);
  --span-secondary: var(--ds-purple-700);
}

/* Default event - Blue */
.eventDefault {
  --event-color: var(--ds-blue-600);
  --span-background: var(--ds-blue-100);
  --span-border: var(--ds-blue-500);
  --span-text: var(--ds-blue-900);
  --span-secondary: var(--ds-blue-700);
}

"use client"

import { clsx } from "clsx"
import type { CSSProperties, MouseEventHandler, ReactNode } from "react"
import { useCallback, useEffect, useLayoutEffect, useRef } from "react"
import { MiniMap } from "./components/map"
import { CursorMarker, EventMarkers, Markers } from "./components/markers"
import { SpanNodes } from "./components/node"
import { SearchBar } from "./components/search"
import { SpanDetailPanel } from "./components/span-detail-panel"
import { ZoomButton } from "./components/zoom-button"
import { TraceViewerContextProvider, useTraceViewer } from "./context"
import styles from "./trace-viewer.module.css"
import type { GetQuickLinks, Trace } from "./types"
import {
  MAP_HEIGHT,
  MARKER_HEIGHT,
  MARKER_NOTCH_HEIGHT,
  ROW_HEIGHT,
  ROW_PADDING,
  SEARCH_GAP,
  SEARCH_HEIGHT,
  TIMELINE_PADDING,
} from "./util/constants"
import { parseTrace } from "./util/tree"
import { useStreamingSpans } from "./util/use-streaming-spans"

interface TraceViewerProps {
  trace?: Trace
  className?: string
  scrollLock?: boolean
  height?: string | number
  withPanel?: boolean
  getQuickLinks?: GetQuickLinks
  highlightedSpans?: string[]
  /** Render all spans immediately (no progressive streaming). */
  eagerRender?: boolean
  /** Whether the trace is live (for continuous tick updates). */
  isLive?: boolean
}

export function TraceViewerProvider({
  getQuickLinks,
  children,
}: Pick<TraceViewerProps, "getQuickLinks"> & {
  children: ReactNode
}): ReactNode {
  return (
    <TraceViewerContextProvider getQuickLinks={getQuickLinks}>
      {children}
    </TraceViewerContextProvider>
  )
}

interface LastClickRef {
  x: number
  y: number
  t: number
  spanId: string
}

const skeletonTrace: Trace = {
  traceId: "skeleton",
  spans: [
    {
      parentSpanId: "",
      spanId: "root",
      name: "root span",
      kind: 1,
      resource: "vercel.runtime",
      startTime: [5000, 0],
      endTime: [6000, 0],
      duration: [1000, 0],
      library: {
        name: "vercel-site",
      },
      status: {
        code: 1,
      },
      attributes: {
        "vercel.ownerId": "team_abc",
      },
      traceFlags: 1,
      events: [],
      links: [],
    },
  ],
  resources: [
    {
      name: "vercel.runtime",
      attributes: {},
    },
  ],
  rootSpanId: "root",
}

function useTimelineLiveTick(isLive: boolean): void {
  const { state, dispatch } = useTraceViewer()
  const stateRef = useRef(state)
  stateRef.current = state

  useEffect(() => {
    if (!isLive) return

    let rafId = 0
    const tick = (): void => {
      const { root } = stateRef.current
      if (root.startTime) {
        const nowMs = Date.now()
        if (nowMs > root.endTime) {
          root.endTime = nowMs
          root.duration = root.endTime - root.startTime
        }
      }
      rafId = requestAnimationFrame(tick)
    }
    rafId = requestAnimationFrame(tick)

    let scaleRafId = 0
    let lastBaseScale = 0
    const scaleTick = (): void => {
      const s = stateRef.current
      if (s.root.duration > 0) {
        const newBaseScale =
          (s.timelineWidth - s.scrollbarWidth) / s.root.duration
        const delta = Math.abs(newBaseScale - lastBaseScale)
        if (delta > lastBaseScale * 0.001 || lastBaseScale === 0) {
          lastBaseScale = newBaseScale
          dispatch({ type: "detectBaseScale" })
        }
      }
      scaleRafId = requestAnimationFrame(scaleTick)
    }
    scaleRafId = requestAnimationFrame(scaleTick)

    return () => {
      cancelAnimationFrame(rafId)
      cancelAnimationFrame(scaleRafId)
    }
  }, [isLive, dispatch])
}

export function TraceViewerTimeline({
  trace = skeletonTrace,
  className = "",
  scrollLock = false,
  height,
  withPanel = false,
  highlightedSpans,
  eagerRender = false,
  isLive = false,
  footer,
  knownDurationMs,
  hasMoreData = false,
  hideSearchBar: hideSearchBarProp = false,
}: Omit<TraceViewerProps, "getQuickLinks"> & {
  footer?: ReactNode
  /** Duration in ms from trace start to the latest known event. Used to render the unknown-time overlay. */
  knownDurationMs?: number
  /** Whether more data pages are expected. Controls the unknown-data overlay visibility. */
  hasMoreData?: boolean
  /** Hide the built-in search bar (e.g. when search is provided externally). */
  hideSearchBar?: boolean
}): ReactNode {
  const isSkeleton = trace === skeletonTrace
  const { state, dispatch } = useTraceViewer()
  const { timelineRef, scrollSnapshotRef } = state
  const memoCache = state.memoCacheRef.current
  const hideSearchBar = (highlightedSpans?.length ?? 0) > 0 || hideSearchBarProp
  const hasRunningSpans = trace.spans.some((span) => span.isRunning)
  const traceHasLiveUpdates = isLive || hasRunningSpans

  useTimelineLiveTick(traceHasLiveUpdates)

  const hasInitializedRef = useRef(false)
  const prevSpanKeyRef = useRef("")
  const prevRootRef = useRef<ReturnType<typeof parseTrace>["root"] | null>(null)
  const prevSpanMapRef = useRef<ReturnType<typeof parseTrace>["map"]>({})
  const prevSizeRef = useRef<{ width: number; height: number } | null>(null)

  useEffect(() => {
    const { root: newRoot, map: newSpanMap } = parseTrace(trace)
    const isInitial = !hasInitializedRef.current
    hasInitializedRef.current = true

    // Build a structural key from span IDs + lightweight event signatures.
    // When only timing changes (same spans and boundary events), we can skip the
    // worker restart. When events change (step completed, etc.) we need a
    // full update because the VisibleSpan objects rendered by React hold
    // copies of the events from the worker — in-place mutation won't reach them.
    const spanKey = Object.keys(newSpanMap)
      .sort()
      .map((id) => {
        const events = newSpanMap[id].events
        const count = events?.length ?? 0
        const first = count ? events?.[0] : undefined
        const last = count ? events?.[count - 1] : undefined
        const eventSignature = `${first?.event.name ?? "none"}@${first?.timestamp ?? 0}|${last?.event.name ?? "none"}@${last?.timestamp ?? 0}`
        return `${id}:${count}:${eventSignature}`
      })
      .join(",")

    if (
      !isInitial &&
      spanKey === prevSpanKeyRef.current &&
      prevRootRef.current
    ) {
      // Same span set, same event counts — only timing changed.
      // Mutate in-place so the worker effect (which depends on root/spanMap
      // references) does NOT restart.
      const oldRoot = prevRootRef.current
      const oldSpanMap = prevSpanMapRef.current
      let didChange = false

      if (
        oldRoot.endTime !== newRoot.endTime ||
        oldRoot.duration !== newRoot.duration
      ) {
        oldRoot.endTime = newRoot.endTime
        oldRoot.duration = newRoot.duration
        didChange = true
      }

      for (const [id, newNode] of Object.entries(newSpanMap)) {
        const oldNode = oldSpanMap[id]
        if (oldNode) {
          if (oldNode.span.isRunning !== newNode.span.isRunning) {
            didChange = true
          }
          if (
            oldNode.endTime !== newNode.endTime ||
            oldNode.duration !== newNode.duration
          ) {
            oldNode.endTime = newNode.endTime
            oldNode.duration = newNode.duration
            didChange = true
          }
          Object.assign(oldNode.span, newNode.span)
        }
      }

      if (!didChange) {
        return
      }

      // Trigger re-render (scale/markers) without restarting the worker.
      // useLiveTick handles continuous scale recalculation for live runs.
      dispatch({ type: "forceRender" })
      return
    }

    // Structure changed or initial load — full dispatch (worker computes new rows)
    prevSpanKeyRef.current = spanKey
    prevRootRef.current = newRoot
    prevSpanMapRef.current = newSpanMap
    dispatch({
      type: isInitial ? "setRoot" : "updateRoot",
      root: newRoot,
      spanMap: newSpanMap,
      resources: trace.resources || [],
    })
  }, [dispatch, trace])

  const { rows, spans, events, scale } = useStreamingSpans(
    highlightedSpans,
    eagerRender
  )

  const ref = useRef<HTMLDivElement>(null)
  useLayoutEffect(() => {
    const $el = ref.current
    if (!$el) return

    const onResize = (): void => {
      const padding = 2 * TIMELINE_PADDING
      const rect = $el.getBoundingClientRect()
      const nextWidth = rect.width - padding
      const nextHeight = rect.height
      const prevSize = prevSizeRef.current

      if (
        prevSize &&
        prevSize.width === nextWidth &&
        prevSize.height === nextHeight
      ) {
        return
      }
      prevSizeRef.current = { width: nextWidth, height: nextHeight }

      dispatch({
        type: "setSize",
        width: nextWidth,
        height: nextHeight,
      })
    }

    onResize()

    const observer = new ResizeObserver(onResize)
    observer.observe($el)
    window.addEventListener("resize", onResize)

    return () => {
      observer.disconnect()
      window.removeEventListener("resize", onResize)
    }
  }, [dispatch])

  const lastClickRef = useRef<LastClickRef>({
    t: 0,
    x: -1,
    y: -1,
    spanId: "",
  })
  const onClick: MouseEventHandler = useCallback(
    (event) => {
      // NOTE(wits): We manually implement double-click logic here so that we can support double
      // clicking a span even if the first click moves the span that the user is clicking on due
      // to the panel opening. If we used a regular double click listener we would need to delay
      // the opening of the panel artificially. This implementation allows us to always be
      // FAST while also avoiding a FRUSTRATING situation.
      const prev = lastClickRef.current
      const t = Date.now()
      const { clientX: x, clientY: y } = event
      const d = Math.sqrt((x - prev.x) ** 2 + (y - prev.y) ** 2)
      // double click
      if (t - prev.t <= 500 && d <= 8) {
        event.stopPropagation()
        event.preventDefault()
        if (!prev.spanId) {
          dispatch({
            type: "resetScale",
          })
          return
        }
        dispatch({
          type: "select",
          id: prev.spanId,
        })
        dispatch({
          type: "scaleToNode",
          id: prev.spanId,
        })
        return
      }
      const target = event.target as HTMLElement
      if (!target.closest(`.${String(styles.timeline)}`)) return
      const $button = target.closest<HTMLButtonElement>("[data-span-id]")
      const spanId = $button?.dataset.spanId || ""
      lastClickRef.current = {
        x,
        y,
        t,
        spanId,
      }
      if (!spanId) return
      dispatch({
        type: "toggleSelection",
        id: spanId,
      })
      event.stopPropagation()
    },
    [dispatch]
  )

  // Zoom helper — apply the scroll snapshot once after a zoom operation so
  // the anchor point stays at the same screen position, then clear it.
  // Without clearing, live runs (where scale changes every frame via
  // detectBaseScale) would continuously reset scrollLeft and prevent the
  // user from scrolling horizontally.
  useLayoutEffect(() => {
    const $timeline = timelineRef.current
    if (!$timeline) return

    const snapshot = scrollSnapshotRef.current
    if (snapshot) {
      $timeline.scrollLeft = snapshot.anchorT * scale - snapshot.anchorX
      scrollSnapshotRef.current = undefined
    }
  }, [scrollSnapshotRef, timelineRef, scale])

  // Selection helper
  useEffect(() => {
    const spanId = state.selected?.span.spanId
    if (!spanId) return

    const timeout = setTimeout(() => {
      const $timeline = state.timelineRef.current
      const $span = $timeline?.querySelector(`[data-span-id="${spanId}"]`)
      if (!$timeline || !$span) return

      const viewRect = $timeline.getBoundingClientRect()
      const spanRect = $span.getBoundingClientRect()

      // If the selected span is narrower than the timeline, scroll it into view
      if (
        spanRect.width < viewRect.width &&
        (spanRect.left < viewRect.left ||
          spanRect.right > viewRect.right ||
          spanRect.top < viewRect.top ||
          spanRect.bottom > viewRect.bottom)
      ) {
        $span.scrollIntoView({
          block: "nearest",
          inline: "center",
          behavior: "smooth",
        })
      }
    }, 500)

    return () => {
      clearTimeout(timeout)
    }
  }, [state.selected, state.timelineRef])

  // Global keyboard shortcuts
  useEffect(() => {
    const onKeyDown = (e: KeyboardEvent): void => {
      if (e.key === "Escape") {
        dispatch({
          type: "escape",
        })
      }
    }
    window.addEventListener("keydown", onKeyDown)

    return () => {
      window.removeEventListener("keydown", onKeyDown)
    }
  }, [dispatch])

  // Scroll locking
  useEffect(() => {
    if (!scrollLock) return

    const $html = document.documentElement
    const $body = document.body

    $html.style.overflow = "clip"
    $body.style.overflow = "clip"

    const onScroll = (event?: Event): void => {
      if (event?.cancelable) {
        event.preventDefault()
      } else {
        window.scrollTo({
          left: 0,
          top: 0,
          behavior: "instant",
        })
      }
    }
    onScroll()
    window.addEventListener("scroll", onScroll, {
      passive: false,
    })

    return () => {
      $html.style.overflow = ""
      $body.style.overflow = ""
      window.removeEventListener("scroll", onScroll)
    }
  }, [scrollLock])

  const timelineHeight = Math.max(
    state.timelineHeight - state.scrollbarWidth,
    MARKER_HEIGHT +
      ROW_PADDING +
      rows.length * (ROW_HEIGHT + ROW_PADDING) -
      ROW_PADDING +
      // When there are enough spans to be near the bottom edge, add some extra padding
      // to avoid overlapping with the zoom buttons, etc.
      84
  )

  const inert = Boolean(state.isMobile && state.selected)

  return (
    <div
      className={clsx(
        styles.traceViewer,
        isSkeleton && styles.skeleton,
        className
      )}
      onClickCapture={onClick}
      ref={ref}
      style={
        {
          height,
          "--timeline-padding": `${TIMELINE_PADDING}px`,
          "--row-height": `${ROW_HEIGHT}px`,
          "--row-padding": `${ROW_PADDING}px`,
          "--search-height": `${!hideSearchBar ? SEARCH_HEIGHT : 0}px`,
          "--search-gap": `${!hideSearchBar ? SEARCH_GAP : 2}px`,
          "--map-height": `${MAP_HEIGHT}px`,
          "--timeline-width": `${state.timelineWidth}px`,
          "--timeline-height": `${state.timelineHeight}px`,
          "--timeline-scroll-width": `${Math.round(state.root.duration * state.scale)}px`,
          "--panel-width": `${state.panelWidth}px`,
          "--panel-height": `${state.panelHeight}px`,
          "--height": `${state.height}px`,
          "--scrollbar-width": `${state.scrollbarWidth}px`,
          "--marker-height": `${MARKER_HEIGHT}px`,
          "--marker-notch-height": `${MARKER_NOTCH_HEIGHT}px`,
        } as CSSProperties
      }
    >
      <MiniMap rows={rows} scale={scale} timelineRef={timelineRef} />
      <div className={clsx(styles.traceViewerContent, inert && styles.inert)}>
        <div className={styles.timeline} ref={timelineRef}>
          <div
            style={{
              position: "relative",
              width: state.timelineWidth,
              minHeight: state.timelineHeight - TIMELINE_PADDING * 2,
              padding: TIMELINE_PADDING,
              paddingBottom: 0,
            }}
          >
            <div
              className={styles.traceNode}
              style={{
                width: state.root.duration * scale || undefined,
                height: timelineHeight - TIMELINE_PADDING * 2,
              }}
            >
              <Markers scale={scale} isLive={traceHasLiveUpdates} />
              <EventMarkers events={events} root={state.root} scale={scale} />
              <CursorMarker
                dispatch={dispatch}
                events={events}
                memoCacheRef={state.memoCacheRef}
                root={state.root}
                scale={scale}
                scrollSnapshotRef={scrollSnapshotRef}
                spans={spans}
                timelineRef={timelineRef}
              />
              <SpanNodes
                cacheKey={memoCache.get("")}
                cache={memoCache}
                customSpanClassNameFunc={state.customSpanClassNameFunc}
                customSpanEventClassNameFunc={
                  state.customSpanEventClassNameFunc
                }
                isLive={isLive}
                root={state.root}
                scale={scale}
                scrollSnapshotRef={scrollSnapshotRef}
                spans={spans}
              />
              {/* Horizontal "unknown time" overlay — covers the region to the
                  right of the latest known event, indicating data beyond this
                  point hasn't been loaded yet. */}
              {knownDurationMs != null &&
                knownDurationMs > 0 &&
                (hasMoreData || traceHasLiveUpdates) &&
                state.root.duration > 0 &&
                (() => {
                  const knownPx = knownDurationMs * scale
                  const totalPx = state.root.duration * scale
                  const unknownWidth = totalPx - knownPx
                  // Only show if the unknown region is meaningfully wide
                  if (unknownWidth < 4) return null
                  // Offset ~5% into the unknown region so it doesn't touch spans
                  const insetPx = Math.min(unknownWidth * 0.05, 20)
                  return (
                    <div
                      style={{
                        position: "absolute",
                        top: 0,
                        left: knownPx + insetPx,
                        width: unknownWidth - insetPx,
                        height: "100%",
                        pointerEvents: "none",
                        zIndex: 1,
                        maskImage:
                          "linear-gradient(to right, transparent 1%, black 3%)",
                        WebkitMaskImage:
                          "linear-gradient(to right, transparent 1%, black 3%)",
                        background:
                          "repeating-linear-gradient(-45deg, var(--ds-background-200) 0, var(--ds-background-200) 11px, var(--ds-gray-200) 11px, var(--ds-gray-200) 12px)",
                      }}
                    />
                  )
                })()}
            </div>
          </div>
          {footer}
        </div>
        <div className={styles.zoomButtonTraceViewer}>
          <ZoomButton />
        </div>
      </div>
      {withPanel ? (
        <div
          className={clsx(
            styles.spanDetailPanelTraceViewer,
            !state.selected && styles.hidden,
            state.isMobile && styles.mobile
          )}
        >
          <SpanDetailPanel attached />
        </div>
      ) : null}
    </div>
  )
}

export function TraceViewerPanel({
  className = "",
  children = null,
}: {
  className?: string
  children?: ReactNode
}): ReactNode {
  const { state } = useTraceViewer()

  if (!state.selected) {
    return children
  }

  return (
    <div
      className={clsx(styles.spanDetailPanelTraceViewer, className)}
      style={
        {
          position: "relative",
          "--search-height": "0",
          "--search-gap": "0",
          "--map-height": "0",
          "--panel-width": `100%`,
          "--panel-height": `100%`,
          "--height": `100%`,
          "--scrollbar-width": `${state.scrollbarWidth}px`,
        } as CSSProperties
      }
    >
      <SpanDetailPanel />
    </div>
  )
}

export function TraceViewer(props: TraceViewerProps): ReactNode {
  return (
    <TraceViewerContextProvider getQuickLinks={props.getQuickLinks} withPanel>
      <TraceViewerTimeline withPanel {...props} />
    </TraceViewerContextProvider>
  )
}

import type { CSSProperties, MutableRefObject, ReactNode } from 'react';

export type MemoCacheKey = Record<string, never>;
export type MemoCache = Map<string, MemoCacheKey>;

export interface Span {
  name: string;
  label?: string;
  className?: string;
  style?: CSSProperties;
  /**
   * When true, the viewer treats this span as still running and keeps its
   * rendered duration growing in real time until the flag is removed.
   */
  isRunning?: boolean;
  kind: number;
  resource: string;
  library: {
    name: string;
    version?: string;
  };
  spanId: string;
  parentSpanId?: string;
  status: {
    code: number;
  };
  traceFlags: number;
  attributes: Record<string, unknown>;
  links: Record<string, unknown>[];
  events: SpanEvent[];
  startTime: [number, number];
  endTime: [number, number];
  duration: [number, number];
  /**
   * The time when the span became active/started executing (optional).
   * If provided and different from startTime, the portion between startTime
   * and activeStartTime will be rendered as a "queued" period with different styling.
   */
  activeStartTime?: [number, number];
}

export interface SpanEvent {
  name: string;
  timestamp: [number, number];
  attributes: Record<string, unknown>;
  /**
   * Optional custom color for this event marker (workflow-specific feature).
   * If provided, this color will be used for the event marker line/diamond.
   */
  color?: string;
  /**
   * Whether to show a vertical line for this event in the timeline (workflow-specific feature).
   * If false, only the diamond marker on the span will be shown.
   * Defaults to true if not specified.
   */
  showVerticalLine?: boolean;
}

export interface Resource {
  name: string;
  attributes: Record<string, string>;
}

export interface Trace {
  traceId: string;
  resources?: Resource[];
  spans: Span[];
  rootSpanId?: string;
}

interface EveryNode {
  startTime: number;
  endTime: number;
  duration: number;
  /**
   * How deep is this node within the tree
   */
  depth: number;
  /**
   * All direct child nodes of this node
   */
  children: SpanNode[];
}

export interface RootNode extends EveryNode {
  /**
   * The depth is always 0 for the root node
   */
  depth: 0;
}

export interface SpanNode extends EveryNode {
  /**
   * This original Span that this node is based on
   */
  span: Span;
  /**
   * The immediate parent of this node
   */
  parent: RootNode | SpanNode;
  /**
   * A generated label to use (overrides the span.name) if present
   */
  label?: string;
  /**
   * OTEL events that are present on this span (e.g. TTFB)
   */
  events?: SpanNodeEvent[];
  /**
   * Whether this span originated in Vercel's infrastructure.
   */
  isVercel: boolean;
  /**
   * Whether this span matches the current search filter
   */
  isHighlighted?: boolean;
  /**
   * Whether this span is a placeholder to hint at where user spans
   * would appear if proper instrumentation were available
   */
  isInstrumentationHint?: boolean;
  /**
   * The index of the resource that this node belongs to (used for color)
   */
  resourceIndex: number;
  /**
   * The time when execution actually started (in milliseconds).
   * If present and greater than startTime, represents a "queued" period.
   */
  activeStartTime?: number;
}

export interface SpanNodeEvent {
  /** A unique key for this event to help with rendering in React */
  key: string;
  /** The timestamp of this event in milliseconds */
  timestamp: number;
  /** The original event model */
  event: SpanEvent;
}

export type TraceNode = RootNode | SpanNode;

export interface VisibleSpan extends SpanNode {
  /**
   * The ref for this span's element in the DOM
   */
  ref?: MutableRefObject<HTMLButtonElement | null>;
  /**
   * The y position of this span (in # of rows)
   */
  row: number;
  /**
   * Whether the CursorMarker is intersecting this span
   */
  isHovered: boolean;
  /**
   * Whether this is the selected span
   */
  isSelected: boolean;
  /**
   * Whether this node is visible (based on its size on screen)
   */
  isVisible: boolean;
  /**
   * Events also need to be able to hold a ref to their element in the DOM
   */
  events?: VisibleSpanEvent[];
}

export interface VisibleSpanEvent extends SpanNodeEvent {
  /**
   * The ref for this span's element in the DOM
   */
  ref?: MutableRefObject<HTMLDivElement | null>;
  /**
   * Whether the CursorMarker is intersecting this span
   */
  isHovered: boolean;
}

export interface ScrollSnapshot {
  anchorT: number;
  anchorX: number;
  scrollLeft: number;
  scrollTop: number;
  startTime: number;
  endTime: number;
  startRow: number;
  endRow: number;
  scale: number;
}

export type WorkerRequest = {
  requestId: number;
} & (
  | {
      type: 'calculateSpanPositions';
      root: RootNode;
    }
  | {
      type: 'filterSpans';
      root: RootNode;
      filter: string;
    }
);

export type WorkerResponse = {
  requestId: number;
} & (
  | {
      type: 'setRowsResult';
      rows: VisibleSpan[][];
      isEnd: boolean;
    }
  | {
      type: 'updateHighlight';
      matches: Set<string>;
    }
);

/**
 * Represents one link to a page related to the selected
 * span in the detail panel.
 */
export interface QuickLink {
  /** Used as a React key and the user-facing name for the link */
  key: string;
  /** Until this Promise is fulfilled, the row will render with a skeleton for the value. */
  value: Promise<QuickLinkValue>;
}

export interface QuickLinkValue {
  /** The visible components for the right side of this link */
  label: ReactNode;
  /** A special suffix to show for this link, defaults to the ExternalLink icon */
  icon?: ReactNode;
  /** The href that this link will open when clicked */
  href: string;
}

export type GetQuickLinks = (node: Span) => QuickLink[];

import type {
  RootNode,
  Span,
  TraceNode,
  VisibleSpan,
  WorkerRequest,
  WorkerResponse,
} from './types';
import { addToRow } from './util/tree';

// The most recent requestId
let requestId = 0;

self.addEventListener('message', (event) => {
  const data = event.data as WorkerRequest;
  requestId = Math.max(requestId, data?.requestId || 0);

  switch (data.type) {
    case 'calculateSpanPositions':
      calculateSpanPositions(data.root);
      break;
    case 'filterSpans':
      filterSpans(data.root, data.filter);
      break;
    default:
      break;
  }
});

const positionHelper = (node: TraceNode, pending: VisibleSpan[]): void => {
  if ('parent' in node) {
    const n = node as VisibleSpan;
    n.row = -1;
    n.isVisible = true;
    pending.push(n);
  }

  const sortedChildren = node.children
    .slice()
    .sort((a, b) => a.startTime - b.startTime || b.duration - a.duration);
  for (const child of sortedChildren) {
    positionHelper(child, pending);
  }
};

const calculateSpanPositions = (root: RootNode): void => {
  const responseId = requestId;
  const placed: VisibleSpan[][] = [];
  const pending: VisibleSpan[] = [];

  positionHelper(root, pending);

  let lastFlushT = Date.now() - 10;
  let lastFlushC = -64;
  let count = 0;
  const flush = (): void => {
    for (const row of placed) {
      row.sort((a, b) => a.startTime - b.startTime);
    }
    const message: WorkerResponse = {
      requestId: responseId,
      type: 'setRowsResult',
      rows: placed,
      isEnd: !pending.length,
    };
    postMessage(message);
    lastFlushT = Date.now();
    lastFlushC = count;
  };

  while (true) {
    const node = pending.shift();
    if (!node) {
      flush();
      return;
    }
    addToRow(placed, node, 0.001);
    ++count;
    if (Date.now() - lastFlushT >= 15 || count - lastFlushC >= 256) {
      flush();
    }
  }
};

const ATTR_FILTER_REGEX = /(?<=^|\s)(?<pair>(?<key>[\w.]+):(?<value>\S*))/g;

const filterSpans = (root: RootNode, filter: string): void => {
  const responseId = requestId;

  const matches = new Set<string>();

  const name = filter
    .replace(ATTR_FILTER_REGEX, '')
    .replace(/\s{2,}/g, ' ')
    .trim();
  const attrs: [string, string][] = [];
  for (const m of filter.matchAll(ATTR_FILTER_REGEX)) {
    const { key = '', value = '' } = m.groups || {};
    attrs.push([key, value.toLocaleLowerCase()]);
  }

  const match = (span: Span): boolean => {
    const nameMatch =
      span.name.toLocaleLowerCase().includes(name) ||
      span.label?.toLocaleLowerCase().includes(name) ||
      span.spanId.toLocaleLowerCase().includes(name);
    if (!nameMatch) return false;
    // TODO: support resource attribute filtering
    return attrs.every(([key, value]) => {
      const v = span.attributes[key];
      if (!v) return false;
      return String(v).toLocaleLowerCase().includes(value);
    });
  };

  const helper = (node: TraceNode): void => {
    for (const child of node.children) {
      if (match(child.span)) {
        matches.add(child.span.spanId);
      }
      helper(child);
    }
  };
  helper(root);

  const message: WorkerResponse = {
    requestId: responseId,
    type: 'updateHighlight',
    matches,
  };
  postMessage(message);
};

import {
  type MutableRefObject,
  memo,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
} from 'react';
import { useTraceViewer } from '../context';
import styles from '../trace-viewer.module.css';
import type { VisibleSpan } from '../types';
import { MAP_HEIGHT, TIMELINE_PADDING } from '../util/constants';
import { useImmediateStyle } from '../util/use-immediate-style';

const getDpi = (): number => {
  if ('devicePixelRatio' in globalThis) {
    return globalThis.devicePixelRatio || 1;
  }
  return 1;
};

const useDpi = (): number => {
  const [dpi, setDpi] = useState(1);
  useLayoutEffect(() => {
    const onChange = (): void => setDpi(getDpi());
    const media = matchMedia(`(resolution: ${dpi}dppx)`);
    media.addEventListener('change', onChange);
    onChange();

    return () => {
      media.removeEventListener('change', onChange);
    };
  }, [dpi]);
  return dpi;
};

const padding = TIMELINE_PADDING;

export const MiniMap = memo(function MiniMap({
  timelineRef,
  rows,
  scale,
}: {
  timelineRef: MutableRefObject<HTMLDivElement | null>;
  rows: VisibleSpan[][];
  scale: number;
}) {
  const {
    state: { root, baseScale, timelineWidth, width: fullWidth, scrollbarWidth },
  } = useTraceViewer();
  const mapWidth = fullWidth + TIMELINE_PADDING * 2;
  const dpi = useDpi();
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const thumbRatio =
    (fullWidth / (fullWidth - scrollbarWidth)) *
    Math.min(fullWidth / timelineWidth, baseScale / scale);
  const thumbWidth = Math.min(
    fullWidth,
    (timelineWidth - scrollbarWidth) * thumbRatio
  );
  useEffect(() => {
    let isHeld = false;
    let clientX = 0;
    let rect: DOMRect | undefined;

    const isValidEventTarget = (target: EventTarget | null): boolean => {
      return Boolean(containerRef.current?.contains(target as HTMLElement));
    };

    let nextFrame = 0;
    const onFrame = (): void => {
      if (!isHeld || !rect) return;
      const $timeline = timelineRef.current;
      if (!$timeline) return;

      const x = clientX - thumbWidth * 0.5 - rect.left;
      $timeline.scrollLeft = x / thumbRatio;
    };

    const onPointerMove = (event: PointerEvent): void => {
      ({ clientX } = event);
      cancelAnimationFrame(nextFrame);
      nextFrame = requestAnimationFrame(onFrame);
    };

    const onPointerDown = (event: PointerEvent): void => {
      if (!isValidEventTarget(event.target)) return;
      isHeld = true;
      rect = containerRef.current?.getBoundingClientRect();
      onPointerMove(event);
    };

    const onPointerUp = (): void => {
      isHeld = false;
      rect = undefined;
    };

    const onTouchStart = (event: TouchEvent): void => {
      if (!isValidEventTarget(event.target)) return;
      if (event.cancelable) {
        event.preventDefault();
      }
    };
    const onTouchMove = (event: TouchEvent): void => {
      if (!isHeld) return;
      if (event.cancelable) {
        event.preventDefault();
      }
    };

    window.addEventListener('pointerdown', onPointerDown);
    window.addEventListener('pointermove', onPointerMove);
    window.addEventListener('pointerup', onPointerUp);
    window.addEventListener('blur', onPointerUp);
    window.addEventListener('touchstart', onTouchStart, { passive: false });
    window.addEventListener('touchmove', onTouchMove, { passive: false });

    return () => {
      window.removeEventListener('pointerdown', onPointerDown);
      window.removeEventListener('pointermove', onPointerMove);
      window.removeEventListener('pointerup', onPointerUp);
      window.removeEventListener('blur', onPointerUp);
      window.removeEventListener('touchstart', onTouchStart);
      window.removeEventListener('touchmove', onTouchMove);
      cancelAnimationFrame(nextFrame);
    };
  }, [timelineRef, thumbRatio, thumbWidth]);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    const render = (): void => {
      ctx.resetTransform();
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.scale(dpi, dpi);

      const gap = 1;
      const height = 3;
      const ratio = (mapWidth - padding * 2) / root.duration;

      // TODO: fill spans based on depth
      ctx.fillStyle = '#ccc';
      ctx.beginPath();
      for (const row of rows) {
        for (const span of row) {
          const y = padding - gap + (gap + height) * span.row;
          if (y >= MAP_HEIGHT - height - padding) break;

          const x = padding + (span.startTime - root.startTime) * ratio;
          const width = span.duration * ratio;

          ctx.roundRect(x, y, width, height, height);
        }
      }
      ctx.fill();
    };

    const nextFrame = requestAnimationFrame(render);

    return () => cancelAnimationFrame(nextFrame);
  }, [dpi, root, mapWidth, rows]);

  const thumbRef = useRef<HTMLDivElement>(null);
  const { style: thumbStyle, setStyle: setThumbStyle } =
    useImmediateStyle(thumbRef);
  useLayoutEffect(() => {
    const $timeline = timelineRef.current;
    if (!$timeline) return;

    let nextFrame = 0;
    const onFrame = (): void => {
      setThumbStyle(
        'transform',
        `translateX(${padding + $timeline.scrollLeft * thumbRatio}px)`
      );
    };
    onFrame();

    const onScroll = (): void => {
      cancelAnimationFrame(nextFrame);
      nextFrame = requestAnimationFrame(onFrame);
    };
    $timeline.addEventListener('scroll', onScroll);

    return () => {
      cancelAnimationFrame(nextFrame);
      $timeline.removeEventListener('scroll', onScroll);
    };
  }, [timelineRef, thumbRatio, setThumbStyle]);

  return (
    <div
      className={styles.mapContainer}
      ref={containerRef}
      style={{
        width: thumbWidth > 0 ? mapWidth : '100%',
        height: MAP_HEIGHT,
      }}
    >
      <canvas
        className={styles.mapCanvas}
        height={MAP_HEIGHT * dpi}
        ref={canvasRef}
        style={{ width: mapWidth, height: MAP_HEIGHT }}
        width={mapWidth * dpi}
      />
      <div
        className={styles.mapThumb}
        ref={thumbRef}
        style={{
          transform: thumbStyle.transform,
          width:
            thumbWidth > 0
              ? thumbWidth
              : `calc(100% - ${TIMELINE_PADDING * 2}px)`,
          top: 2,
          height: MAP_HEIGHT - 4,
        }}
      />
    </div>
  );
});

'use client';

import { clsx } from 'clsx';
import type {
  CSSProperties,
  Dispatch,
  MutableRefObject,
  ReactNode,
} from 'react';
import { useEffect, useMemo, useRef, useState } from 'react';
import { type TraceViewerAction, useTraceViewer } from '../context';
import styles from '../trace-viewer.module.css';
import type {
  MemoCache,
  RootNode,
  ScrollSnapshot,
  VisibleSpan,
  VisibleSpanEvent,
} from '../types';
import {
  MARKER_HEIGHT,
  ROW_HEIGHT,
  ROW_PADDING,
  TIMELINE_PADDING,
} from '../util/constants';
import {
  formatDurationForTimeline,
  formatTimeSelection,
  formatWallClockTime,
} from '../util/timing';
import { useImmediateStyle } from '../util/use-immediate-style';
import { useTrackpadZoom } from '../util/use-trackpad-zoom';

/**
 * Snap a raw duration to the nearest "nice" number in the 1-2-5 × 10^n
 * sequence (e.g. …, 0.5, 1, 2, 5, 10, 20, 50, 100, …).
 */
function snapToNice(raw: number): number {
  if (raw <= 0) return 1;
  const log10 = Math.floor(Math.log10(raw));
  const pow = 10 ** log10;
  const normalized = raw / pow;

  if (normalized <= 1.5) return pow;
  if (normalized <= 3.5) return 2 * pow;
  if (normalized <= 7.5) return 5 * pow;
  return 10 * pow;
}

export function Markers({
  scale,
  isLive = false,
}: {
  scale: number;
  isLive?: boolean;
}): ReactNode {
  const {
    state: { root },
  } = useTraceViewer();
  // Force a re-render every second when live to pick up new tick marks.
  // The markers container width is grown at 60fps by useLiveTick;
  // this interval only ensures the marker *labels* stay current.
  const [, forceMarkerUpdate] = useState(0);
  useEffect(() => {
    if (!isLive) return;
    const id = setInterval(() => forceMarkerUpdate((v) => v + 1), 1000);
    return () => clearInterval(id);
  }, [isLive]);

  const fullDuration = root.duration;

  // Calculate a marker interval that gives reasonable spacing at any zoom level.
  // We target ~50px per notch mark; labels appear on every Nth notch via labelSpacing.
  // When scale is <= 0 (e.g. the initial -1 sentinel), fall back to a safe default
  // to avoid generating an absurd number of markers.
  const effectiveScale =
    scale > 0 ? scale : fullDuration > 0 ? 1 / fullDuration : 1;
  const targetNotchPx = 50;
  let markerDuration = snapToNice(targetNotchPx / effectiveScale);
  markerDuration = Math.max(1, markerDuration);
  let markerWidth = markerDuration * effectiveScale;

  // Cap marker count to avoid creating too many DOM elements at extreme zoom
  // on very long traces.  Only the visible portion is shown on screen anyway.
  const MAX_MARKERS = 1000;
  if (fullDuration / markerDuration > MAX_MARKERS) {
    markerDuration = snapToNice(fullDuration / MAX_MARKERS);
    markerWidth = markerDuration * effectiveScale;
  }
  const markerCount = Math.ceil(fullDuration / markerDuration);

  // How often labels should appear for markers, e.g. 3 === one label for every third marker
  const labelSpacing = Math.ceil(100 / markerWidth) || 1;

  return (
    <div className={styles.markersContainer}>
      <div
        aria-hidden
        className={styles.markers}
        style={
          {
            width: Math.floor(root.duration * scale + 15),
            visibility: scale !== -1 ? 'visible' : 'hidden',
            '--marker-width': `${markerWidth}px`,
          } as CSSProperties
        }
      >
        {new Array(markerCount).fill(null).map((_, i) => {
          const hasLabel = i % labelSpacing === 0;
          return (
            <span
              className={clsx(styles.marker, !hasLabel && styles.notch)}
              key={String(i)}
            >
              {hasLabel ? (
                <span className={styles.markerLabel}>
                  {formatDurationForTimeline(markerDuration * i)}
                  <span className={styles.markerClockTime}>
                    {formatWallClockTime(root.startTime + markerDuration * i)}
                  </span>
                </span>
              ) : null}
            </span>
          );
        })}
      </div>
    </div>
  );
}

export function EventMarkers({
  events,
  root,
  scale,
}: {
  events: VisibleSpanEvent[];
  root: RootNode;
  scale: number;
}): ReactNode {
  // Filter out events that should not show vertical lines (workflow-specific feature)
  const eventsWithVerticalLines = useMemo(
    () => events.filter((x) => x.event.showVerticalLine !== false),
    [events]
  );

  return (
    <div className={styles.eventMarkersContainer}>
      <div
        aria-hidden
        className={styles.eventMarkers}
        style={
          {
            width: Math.floor(root.duration * scale),
          } as CSSProperties
        }
      >
        {eventsWithVerticalLines.map((x) => {
          return (
            <span
              className={clsx(styles.eventMarker)}
              key={x.key}
              style={{
                left: Math.floor((x.timestamp - root.startTime) * scale),
                ...(x.event.color && { borderLeftColor: x.event.color }),
              }}
            />
          );
        })}
      </div>
    </div>
  );
}

const HOVER_OVERSCAN = 2;

interface TrackpadZoom {
  anchorX: number;
  anchorT: number;
}

export function CursorMarker({
  memoCacheRef,
  timelineRef,
  root,
  spans,
  events,
  scale,
  dispatch,
  scrollSnapshotRef,
}: {
  memoCacheRef: MutableRefObject<MemoCache>;
  timelineRef: MutableRefObject<HTMLDivElement | null>;
  root: RootNode;
  spans: VisibleSpan[];
  events: VisibleSpanEvent[];
  scale: number;
  dispatch: Dispatch<TraceViewerAction>;
  scrollSnapshotRef: MutableRefObject<ScrollSnapshot | undefined>;
}): ReactNode {
  const hasEnteredRef = useRef(false);
  const spansRef = useRef(spans);
  spansRef.current = spans;
  const eventsRef = useRef(events);
  eventsRef.current = events;
  const labelRef = useRef<HTMLDivElement>(null);
  const { style: labelStyle, setStyle: setLabelStyle } =
    useImmediateStyle(labelRef);
  const labelTextRef = useRef<HTMLDivElement>(null);

  const ref = useRef<HTMLDivElement>(null);
  const { style, setStyle } = useImmediateStyle(ref);
  const rectRef = useRef<DOMRect>(undefined);

  const selectionRef = useRef<HTMLDivElement>(null);
  const { style: selectionStyle, setStyle: setSelectionStyle } =
    useImmediateStyle(selectionRef);

  const xRef = useRef(0);
  useEffect(() => {
    const $timeline = timelineRef.current;
    if (!$timeline) return;

    let x = xRef.current;
    let xStart = 0;
    let isDragging = false;
    let isExternalDrag = false;
    let hasMoved = false;
    let isRightClick = false;
    let scrollX = 0;
    let scrollY = 0;
    const hoverStartT = Date.now() + 500;
    const updateRect = (): void => {
      if (rectRef.current) return;
      rectRef.current = $timeline.getBoundingClientRect();
    };

    const getRowFromY = (y: number): number => {
      if (!rectRef.current) return 0;
      return (
        (y - MARKER_HEIGHT - TIMELINE_PADDING) / (ROW_HEIGHT + ROW_PADDING)
      );
    };

    const removeHover = (): void => {
      const cache = memoCacheRef.current;
      // Remove hover styling from any elements that have it
      for (const span of spansRef.current) {
        if (!span.isHovered) continue;
        span.isHovered = false;
        cache.set(span.span.spanId, {});
      }
      dispatch({
        type: 'forceRender',
      });
    };

    let nextFrame = 0;
    const onFrame = (): void => {
      if (!hasEnteredRef.current) return;
      if (!rectRef.current) updateRect();
      const rect = rectRef.current;
      if (!rect) return;

      const { scrollLeft, scrollTop } = $timeline;

      const left = Math.max(
        0,
        Math.min(
          x + scrollLeft - rect.left - TIMELINE_PADDING,
          root.duration * scale
        )
      );
      const leftStyle = `${left - scrollLeft + TIMELINE_PADDING}px`;
      setStyle('left', leftStyle);
      setLabelStyle('left', leftStyle);

      const t = root.startTime + left / scale;
      const labelT = t - root.startTime;
      if (labelT < 0 || labelT > root.duration) {
        labelTextRef.current?.removeAttribute('data-text');
      } else {
        labelTextRef.current?.setAttribute(
          'data-text',
          formatTimeSelection(labelT)
        );
      }

      if (isDragging) {
        const xDelta = x - xStart;
        const width = Math.abs(xDelta);
        if (!hasMoved) {
          if (width < 4) return;
          hasMoved = true;
          setSelectionStyle('display', 'flex');
          removeHover();
        }

        if (xDelta > 0) {
          setSelectionStyle('left', '');
          setSelectionStyle('right', '0');
        } else {
          setSelectionStyle('left', '0');
          setSelectionStyle('right', '');
        }
        setSelectionStyle('width', `${width}px`);

        const leftStart = Math.max(
          0,
          Math.min(
            xStart + scrollLeft - rect.left - TIMELINE_PADDING,
            root.duration * scale
          )
        );
        const labelTStart = leftStart / scale;
        let t1: number;
        let t2: number;
        if (labelTStart < labelT) {
          t1 = labelTStart;
          t2 = labelT;
        } else {
          t1 = labelT;
          t2 = labelTStart;
        }
        selectionRef.current?.setAttribute(
          'data-range',
          `${formatTimeSelection(t1)} — ${formatTimeSelection(t2)}`
        );
        selectionRef.current?.setAttribute(
          'data-duration',
          `${formatTimeSelection(t2 - t1)} selected`
        );
      }

      if (Date.now() < hoverStartT) {
        nextFrame = requestAnimationFrame(onFrame);
        return;
      }

      if (scrollLeft !== scrollX || scrollTop !== scrollY) {
        scrollX = scrollLeft;
        scrollY = scrollTop;
        nextFrame = requestAnimationFrame(onFrame);
        return;
      }

      if (x - rect.left < 128) {
        labelTextRef.current?.setAttribute('data-align', 'left');
      } else if (x - rect.left > rect.width - 128) {
        labelTextRef.current?.setAttribute('data-align', 'right');
      } else {
        labelTextRef.current?.removeAttribute('data-align');
      }

      if (!hasMoved && !isExternalDrag) {
        const cache = memoCacheRef.current;

        // Span Hover
        const rowMin = getRowFromY(scrollTop) - HOVER_OVERSCAN;
        const rowMax = getRowFromY(scrollTop + rect.height) + HOVER_OVERSCAN;
        for (const span of spansRef.current) {
          const isHovered =
            span.row >= rowMin &&
            span.row <= rowMax &&
            t >= span.startTime &&
            t <= span.endTime;
          if (span.isHovered === isHovered) continue;
          span.isHovered = isHovered;
          cache.set(span.span.spanId, {});
        }

        // Event Hover — only show the nearest event when multiple overlap
        const eventSpreadPx = 12;
        const eventSpreadMs = eventSpreadPx / scale;
        let closestEvent: (typeof eventsRef.current)[number] | null = null;
        let closestDist = Infinity;
        for (const event of eventsRef.current) {
          const dist = Math.abs(event.timestamp - t);
          if (dist <= eventSpreadMs && dist < closestDist) {
            closestDist = dist;
            closestEvent = event;
          }
        }
        for (const event of eventsRef.current) {
          const isHovered = event === closestEvent;
          if (event.isHovered === isHovered) continue;
          event.isHovered = isHovered;
          const $event = event.ref?.current;
          if (!$event) continue;
          $event.setAttribute('data-hovered', String(isHovered));
        }

        dispatch({
          type: 'forceRender',
        });
      }
    };
    nextFrame = requestAnimationFrame(onFrame);

    const onPointerEnter = (event: PointerEvent): void => {
      if (event.pointerType !== 'mouse') return;
      hasEnteredRef.current = true;
    };
    const onPointerLeave = (): void => {
      if (!hasEnteredRef.current) return;
      hasEnteredRef.current = false;
      removeHover();
    };

    const onMouseMove = ({ clientX }: MouseEvent): void => {
      x = clientX;
      xRef.current = x;
      cancelAnimationFrame(nextFrame);
      nextFrame = requestAnimationFrame(onFrame);
    };

    const onContextMenu = (event: MouseEvent): void => {
      event.preventDefault();
    };
    const onMouseDown = (event: MouseEvent): void => {
      if (event.button === 2) {
        isRightClick = true;
        event.preventDefault();
      } else if (event.button !== 0) {
        return;
      } else {
        isRightClick = false;
      }
      if (timelineRef.current?.contains(event.target as HTMLElement)) {
        xStart = x;
        isDragging = true;
      } else {
        isExternalDrag = true;
        requestAnimationFrame(removeHover);
      }
    };
    const onMouseUp = (event: Event): void => {
      isExternalDrag = false;

      if (!isDragging) return;
      isDragging = false;

      if (!hasMoved) return;
      hasMoved = false;
      setSelectionStyle('display', '');
      setSelectionStyle('left', '');
      setSelectionStyle('right', '');
      setSelectionStyle('width', '');

      event.preventDefault();
      event.stopImmediatePropagation();

      if (isRightClick) {
        isRightClick = false;
        return;
      }

      if (!rectRef.current) updateRect();
      const rect = rectRef.current;
      if (!rect) return;

      const { scrollLeft } = $timeline;

      const start = Math.max(
        0,
        Math.min(
          (xStart + scrollLeft - rect.left - TIMELINE_PADDING) / scale,
          root.duration
        )
      );
      const end = Math.max(
        0,
        Math.min(
          (x + scrollLeft - rect.left - TIMELINE_PADDING) / scale,
          root.duration
        )
      );

      dispatch({
        type: 'scaleToRange',
        t1: start + root.startTime,
        t2: end + root.startTime,
      });
    };

    const onKeyDown = (event: KeyboardEvent): void => {
      if (!isDragging) return;
      if (event.key !== 'Escape') return;

      isRightClick = true;
      onMouseUp(event);
    };

    const onWindowScroll = (): void => {
      rectRef.current = undefined;
      trackpadZoomRef.current = undefined;
      cancelAnimationFrame(nextFrame);
      nextFrame = requestAnimationFrame(onFrame);
    };

    const onScroll = (): void => {
      cancelAnimationFrame(nextFrame);
      nextFrame = requestAnimationFrame(onFrame);
    };

    const observer = new ResizeObserver(() => {
      // NOTE: I tried to use the entry from this to immediately set the rect,
      // but for some reason it has different dimensions than the one from
      // .getBoundingClientRect()
      rectRef.current = undefined;
    });
    observer.observe($timeline);

    window.addEventListener('mousemove', onMouseMove);
    $timeline.addEventListener('contextmenu', onContextMenu);
    window.addEventListener('mousedown', onMouseDown);
    window.addEventListener('mouseup', onMouseUp);
    window.addEventListener('blur', onMouseUp);
    window.addEventListener('keydown', onKeyDown, true);
    window.addEventListener('scroll', onWindowScroll);
    $timeline.addEventListener('scroll', onScroll);
    $timeline.addEventListener('pointerenter', onPointerEnter);
    $timeline.addEventListener('pointerleave', onPointerLeave);

    return () => {
      observer.disconnect();
      window.removeEventListener('mousemove', onMouseMove);
      $timeline.removeEventListener('contextmenu', onContextMenu);
      window.removeEventListener('mousedown', onMouseDown);
      window.removeEventListener('mouseup', onMouseUp);
      window.removeEventListener('blur', onMouseUp);
      window.removeEventListener('keydown', onKeyDown, true);
      window.removeEventListener('scroll', onWindowScroll);
      $timeline.removeEventListener('scroll', onScroll);
      $timeline.removeEventListener('pointerenter', onPointerEnter);
      $timeline.removeEventListener('pointerleave', onPointerLeave);
      cancelAnimationFrame(nextFrame);
      xRef.current = x;
      removeHover();
    };
  }, [
    dispatch,
    root,
    scale,
    setStyle,
    setLabelStyle,
    setSelectionStyle,
    memoCacheRef,
    timelineRef,
    scrollSnapshotRef,
  ]);

  const trackpadZoomRef = useRef<TrackpadZoom>(undefined);
  useTrackpadZoom((delta) => {
    const $timeline = timelineRef.current;
    if (!$timeline) return;

    rectRef.current ??= $timeline.getBoundingClientRect();
    const rect = rectRef.current;
    const anchorX = Math.max(
      0,
      Math.min(
        xRef.current - rect.left - TIMELINE_PADDING,
        rect.width - 2 * TIMELINE_PADDING
      )
    );

    let anchorT = 0;
    let existing = trackpadZoomRef.current;
    if (existing?.anchorX === anchorX) {
      anchorT = existing.anchorT;
    } else {
      anchorT = ($timeline.scrollLeft + anchorX) / scale;
      existing = {
        anchorT,
        anchorX,
      };
      trackpadZoomRef.current = existing;
    }

    dispatch({
      type: 'trackpadScale',
      delta: delta / 64,
      anchorT,
      anchorX,
    });
  });

  return (
    <>
      <div className={styles.cursorMarkerStickyParent}>
        <div
          className={styles.cursorMarkerLabelContainer}
          ref={labelRef}
          style={labelStyle}
        >
          <div className={styles.cursorMarkerLabel} ref={labelTextRef} />
        </div>
      </div>
      <div className={styles.cursorMarkerStickyParent}>
        <div className={styles.cursorMarkerContainer} ref={ref} style={style}>
          <div className={styles.cursorMarker}>
            <div
              className={styles.cursorSelection}
              ref={selectionRef}
              style={selectionStyle}
            />
          </div>
        </div>
      </div>
    </>
  );
}

'use client';

import { clsx } from 'clsx';
import type { CSSProperties, MutableRefObject, ReactNode } from 'react';
import { memo, useEffect, useRef, useState } from 'react';
import styles from '../trace-viewer.module.css';
import type {
  MemoCache,
  MemoCacheKey,
  RootNode,
  ScrollSnapshot,
  SpanNode,
  VisibleSpan,
  VisibleSpanEvent,
} from '../types';
import { MARKER_HEIGHT, ROW_HEIGHT, ROW_PADDING } from '../util/constants';
import { formatDuration, getHighResInMs } from '../util/timing';
import { SpanContent } from './span-content';
import { computeSegments } from './span-segments';
import {
  type ResourceType,
  type SpanLayout,
  getResourceType,
  getSpanLayout,
} from './span-strategies';

export const getSpanColorClassName = (node: SpanNode): string => {
  if (node.isVercel) return String(styles.colorVercel);
  return String(styles[`color${node.resourceIndex % 5}` as 'color0']);
};

function getTerminalTimestamp(
  resourceType: ResourceType,
  node: VisibleSpan
): number | undefined {
  const events = node.events;
  if (!events?.length) return undefined;

  switch (resourceType) {
    case 'hook':
      for (let i = events.length; i--; ) {
        if (events[i].event.name === 'hook_disposed') {
          return events[i].timestamp;
        }
      }
      return undefined;
    case 'sleep':
      for (let i = events.length; i--; ) {
        if (events[i].event.name === 'wait_completed') {
          return events[i].timestamp;
        }
      }
      return undefined;
    case 'run':
      for (let i = events.length; i--; ) {
        const name = events[i].event.name;
        if (
          name === 'run_completed' ||
          name === 'run_failed' ||
          name === 'run_cancelled'
        ) {
          return events[i].timestamp;
        }
      }
      return undefined;
    case 'step':
      for (let i = events.length; i--; ) {
        const name = events[i].event.name;
        if (name === 'step_completed' || name === 'step_failed') {
          return events[i].timestamp;
        }
        if (name === 'step_started' || name === 'step_retrying') {
          return undefined;
        }
      }
      return undefined;
    default:
      return undefined;
  }
}

export const SpanNodes = memo(function SpanNodes({
  root,
  scale,
  spans,
  isLive = false,
  scrollSnapshotRef,
  cache,
  customSpanClassNameFunc,
  customSpanEventClassNameFunc,
}: {
  root: RootNode;
  scale: number;
  spans: VisibleSpan[];
  isLive?: boolean;
  scrollSnapshotRef: MutableRefObject<ScrollSnapshot | undefined>;
  /** Not used in the body — exists solely to bust React.memo when the global memo cache changes. */
  cacheKey?: MemoCacheKey;
  cache: MemoCache;
  customSpanClassNameFunc?: (span: SpanNode) => string;
  customSpanEventClassNameFunc?: (event: VisibleSpanEvent) => string;
}) {
  return spans.map((x) => (
    <SpanComponent
      cacheKey={cache.get(x.span.spanId)}
      customSpanEventClassNameFunc={customSpanEventClassNameFunc}
      customSpanClassNameFunc={customSpanClassNameFunc}
      key={x.span.spanId}
      node={x}
      root={root}
      scale={scale}
      traceIsLive={isLive}
      scrollSnapshotRef={scrollSnapshotRef}
    />
  ));
});

// ──────────────────────────────────────────────────────────────────────────
// Compute inline styles from a SpanLayout
// ──────────────────────────────────────────────────────────────────────────

function getSpanStyle(
  layout: SpanLayout,
  node: VisibleSpan,
  root: RootNode,
  scale: number
): CSSProperties {
  // Use isExpanded (hovered or selected) for width expansion so that
  // selected small spans stay expanded and show their name.
  const expanded = layout.isExpanded;
  return {
    // Use actualWidth for CSS variable so hover expansion is accurate
    '--span-width': `${Math.max(layout.actualWidth, 1)}px`,
    minWidth: expanded ? layout.width : undefined,
    width: expanded ? undefined : layout.width,
    height: layout.height,
    maxWidth:
      expanded && !layout.isNearRightSide
        ? (root.endTime - node.startTime) * scale
        : undefined,
    containIntrinsicWidth: expanded ? undefined : layout.width,
    containIntrinsicHeight: layout.height,
    left: layout.isNearRightSide ? undefined : layout.left,
    right: layout.isNearRightSide
      ? (root.endTime - node.endTime) * scale
      : undefined,
    top: layout.top,
  } as CSSProperties;
}

// ──────────────────────────────────────────────────────────────────────────
// SpanComponent
// ──────────────────────────────────────────────────────────────────────────

export const SpanComponent = memo(function SpanComponent({
  node,
  root,
  scale,
  traceIsLive = false,
  scrollSnapshotRef,
  customSpanClassNameFunc,
  customSpanEventClassNameFunc,
}: {
  node: VisibleSpan;
  root: RootNode;
  scale: number;
  traceIsLive?: boolean;
  scrollSnapshotRef: MutableRefObject<ScrollSnapshot | undefined>;
  /** Not used in the body — exists solely to bust React.memo for this span. */
  cacheKey?: MemoCacheKey;
  customSpanClassNameFunc?: (span: SpanNode) => string;
  customSpanEventClassNameFunc?: (event: VisibleSpanEvent) => string;
}): ReactNode {
  const ref = useRef<HTMLButtonElement>(null);

  useEffect(() => {
    node.ref = ref;
    return () => {
      node.ref = undefined;
    };
  }, [node]);

  const { span } = node;
  const resourceType = getResourceType(node);
  const [liveNow, setLiveNow] = useState(0);

  // Get custom class name from callback if provided
  const customClassName = customSpanClassNameFunc
    ? customSpanClassNameFunc(node)
    : '';

  // Workflow span types use colored segments + boundary line markers
  // Generic OTEL spans use diamond event markers
  const isWorkflowSpan = resourceType !== 'default';

  // Determine if this span is still active (live). We require the parent run
  // to be explicitly live to avoid completed/cancelled traces continuing to
  // grow due to timing heuristics.
  const data = span.attributes?.data as Record<string, unknown> | undefined;
  const terminalTimestamp = getTerminalTimestamp(resourceType, node);
  const hasTerminalEvent = terminalTimestamp != null;
  const isCompletedByData =
    resourceType === 'hook'
      ? Boolean(data?.disposedAt)
      : Boolean(data?.completedAt);
  const isCompleted = isCompletedByData || hasTerminalEvent;
  const isExplicitlyRunning = Boolean(span.isRunning);
  const isInferredLive = traceIsLive && isWorkflowSpan && !isCompleted;
  const isLive = isExplicitlyRunning || isInferredLive;

  useEffect(() => {
    if (!isLive) return;
    setLiveNow(Date.now());
    const interval = setInterval(() => {
      setLiveNow(Date.now());
    }, 250);
    return () => clearInterval(interval);
  }, [isLive]);

  const canonicalStartTime = getHighResInMs(span.startTime);
  const canonicalEndTime = getHighResInMs(span.endTime);
  const canonicalDuration = getHighResInMs(span.duration);
  const canonicalActiveStartTime = span.activeStartTime
    ? getHighResInMs(span.activeStartTime)
    : undefined;

  const durationMs =
    isExplicitlyRunning
      ? Math.max(0, (liveNow || Date.now()) - canonicalStartTime)
      : terminalTimestamp != null
      ? Math.max(0, terminalTimestamp - canonicalStartTime)
      : isLive
        ? Math.max(0, (liveNow || Date.now()) - canonicalStartTime)
        : canonicalDuration;
  const duration = node.isInstrumentationHint
    ? 'Get Started'
    : formatDuration(durationMs);
  const baseNode = {
    ...node,
    startTime: canonicalStartTime,
    endTime: canonicalEndTime,
    duration: canonicalDuration,
    activeStartTime: canonicalActiveStartTime,
  } as VisibleSpan;
  const segmentNode = isLive
    ? ({
        ...baseNode,
        duration: durationMs,
        endTime: canonicalStartTime + durationMs,
      } as VisibleSpan)
    : baseNode;
  const hasSegments =
    isWorkflowSpan &&
    computeSegments(resourceType, segmentNode).segments.length > 0;
  const layout = getSpanLayout(
    resourceType,
    segmentNode,
    root,
    scale,
    scrollSnapshotRef
  );

  // For live spans the data-level `node.duration` can be stale (from the last
  // fetch) while the visual width is growing via rAF. Recompute from real
  // elapsed time so that:
  //  - height/isSmall classification stays correct (not shrunken to 40%)
  //  - React-rendered width matches the rAF-driven width, preventing a brief
  //    shrink→expand flash on re-render that breaks cursor hit-testing
  if (isLive) {
    const elapsed = durationMs;
    const liveActualWidth = elapsed * scale;
    const liveWidth = Math.max(liveActualWidth, 4);
    layout.actualWidth = liveActualWidth;
    layout.width = liveWidth;
    layout.isSmall = liveActualWidth < 64;
    layout.isHuge = liveActualWidth >= 500;
    if (!layout.isSmall) {
      layout.height = ROW_HEIGHT;
      layout.top = MARKER_HEIGHT + (ROW_HEIGHT + ROW_PADDING) * segmentNode.row;
    }
  }

  // Smoothly grow active span width at 60fps using wall clock time
  useEffect(() => {
    if (!isLive || !ref.current) return;

    let rafId = 0;
    const tick = (): void => {
      const $el = ref.current;
      if (!$el) return;
      const elapsed = Date.now() - canonicalStartTime;
      const w = Math.max(elapsed * scale, 2);
      $el.style.width = `${w}px`;
      $el.style.setProperty('--span-width', `${w}px`);
      rafId = requestAnimationFrame(tick);
    };
    rafId = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafId);
  }, [isLive, canonicalStartTime, scale]);

  const renderNode = segmentNode;

  return (
    <>
      <button
        aria-label={`${span.name} - ${duration}`}
        className={clsx(
          styles.spanNode,
          layout.isHuge && styles.huge,
          layout.isSmall && styles.small,
          layout.isExpanded && styles.xHover,
          node.isHighlighted
            ? styles.colorHighlight
            : getSpanColorClassName(node),
          node.isHighlighted === false && styles.unlit,
          customClassName,
          hasSegments && styles.hasSegments
        )}
        data-span-id={span.spanId}
        data-start-time={segmentNode.startTime - root.startTime}
        data-right-side={layout.isNearRightSide}
        data-running={isLive ? '' : undefined}
        data-selected={node.isSelected ? '' : undefined}
        ref={ref}
        style={{
          ...getSpanStyle(layout, segmentNode, root, scale),
          ...(span.style ?? {}),
        }}
        type="button"
      >
        <SpanContent
          durationMs={durationMs}
          resourceType={resourceType}
          node={renderNode}
          layout={layout}
        />
      </button>
      {segmentNode.events && !layout.isSmall
        ? segmentNode.events.map((x) => (
            <SpanEventComponent
              customSpanEventClassNameFunc={customSpanEventClassNameFunc}
              event={x}
              key={x.key}
              node={segmentNode}
              root={root}
              scale={scale}
              asBoundary={isWorkflowSpan}
            />
          ))
        : null}
    </>
  );
});

// ──────────────────────────────────────────────────────────────────────────
// SpanEventComponent
// ──────────────────────────────────────────────────────────────────────────

/** Human-readable labels for workflow event types */
const BOUNDARY_LABELS: Record<string, string> = {
  step_started: 'Started',
  step_retrying: 'Retrying',
  step_failed: 'Failed',
  hook_created: 'Created',
  hook_received: 'Received',
  hook_disposed: 'Resolved',
  wait_created: 'Sleep started',
  wait_completed: 'Sleep completed',
  run_started: 'Started',
  run_completed: 'Completed',
  run_failed: 'Run failed',
  step_completed: 'Completed',
};

export const SpanEventComponent = memo(function SpanEventComponent({
  event,
  node,
  root,
  scale,
  customSpanEventClassNameFunc,
  asBoundary = false,
}: {
  event: VisibleSpanEvent;
  node: VisibleSpan;
  root: RootNode;
  scale: number;
  customSpanEventClassNameFunc?: (event: VisibleSpanEvent) => string;
  asBoundary?: boolean;
}): ReactNode {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    event.ref = ref;
    return () => {
      event.ref = undefined;
    };
  }, [event]);

  const {
    event: { name },
  } = event;
  const timestamp = formatDuration(event.timestamp - root.startTime);
  const displayLabel = asBoundary ? (BOUNDARY_LABELS[name] ?? name) : name;

  // For boundary events, compute the duration of the phase.
  // "Forward" events (started, retrying) measure until the next event.
  // "Terminal" events (completed) measure from the previous started event.
  const isForwardEvent =
    asBoundary &&
    (name === 'step_started' ||
      name === 'run_started' ||
      name === 'step_retrying');
  const isTerminalEvent =
    asBoundary && (name === 'step_completed' || name === 'run_completed');

  let phaseDuration: string | null = null;
  let phaseLabel: string | null = null;
  if ((isForwardEvent || isTerminalEvent) && node.events) {
    const sortedNodeEvents = [...node.events].sort(
      (a, b) => a.timestamp - b.timestamp
    );
    const currentIdx = sortedNodeEvents.findIndex((e) => e.key === event.key);

    if (isTerminalEvent) {
      // Look backward to find the last step_started
      let prevStartTime: number | null = null;
      for (let i = currentIdx - 1; i >= 0; i--) {
        if (sortedNodeEvents[i].event.name === 'step_started') {
          prevStartTime = sortedNodeEvents[i].timestamp;
          break;
        }
      }
      if (prevStartTime !== null) {
        phaseDuration = formatDuration(event.timestamp - prevStartTime);
        phaseLabel = 'Executed';
      }
    } else {
      // Look forward to the next event
      const nextEvent = sortedNodeEvents[currentIdx + 1];
      const endTime = nextEvent ? nextEvent.timestamp : node.endTime;
      phaseDuration = formatDuration(endTime - event.timestamp);
      phaseLabel = name === 'step_retrying' ? 'Waited' : 'Executed';
    }
  }

  const left = (event.timestamp - root.startTime) * scale;
  const top = MARKER_HEIGHT + (ROW_HEIGHT + ROW_PADDING) * node.row;
  const isLeftAligned =
    node.duration <= 0 ||
    (event.timestamp - node.startTime) / node.duration < 0.5;

  // Get custom class name from callback if provided
  const customClassName = customSpanEventClassNameFunc
    ? customSpanEventClassNameFunc(event)
    : '';

  return (
    <div
      title={
        phaseDuration
          ? `${displayLabel} ${timestamp}\n${phaseLabel} ${phaseDuration}`
          : `${displayLabel} ${timestamp}`
      }
      className={clsx(
        styles.spanNodeEvent,
        customClassName,
        asBoundary && styles.boundaryMarker,
        node.isHighlighted
          ? styles.colorHighlight
          : getSpanColorClassName(node),
        node.isHighlighted === false && styles.unlit
      )}
      data-hovered={event.isHovered}
      ref={ref}
      style={
        {
          left,
          top,
        } as CSSProperties
      }
    >
      <div
        className={clsx(
          styles.hoverInfo,
          isLeftAligned ? styles.alignStart : styles.alignEnd
        )}
      >
        {asBoundary ? (
          <>
            <span className={styles.eventName}>{displayLabel}</span>
            <span className={styles.eventTimestamp}>{timestamp}</span>
            {phaseDuration ? (
              <>
                <span className={styles.eventName}>{phaseLabel}</span>
                <span className={styles.eventTimestamp}>{phaseDuration}</span>
              </>
            ) : null}
          </>
        ) : (
          <>
            <span className={styles.eventName}>{name}</span>
            <span className={styles.eventTimestamp}>{timestamp}</span>
          </>
        )}
      </div>
      {asBoundary ? (
        <div className={styles.boundaryLine} />
      ) : (
        <div className={styles.eventDiamond} />
      )}
    </div>
  );
});

import type { ChangeEventHandler, ReactNode } from 'react';
import styles from '../trace-viewer.module.css';

export function SearchInput({
  height,
  width,
  value,
  placeholder,
  onChange,
}: {
