          <>
            {link.label}
            {link.icon || <IconExternalSmall color="gray-900" />}
          </>
        ) : (
          <>
            <Skeleton height={18} width={32 + name.length * 8} />
            <Skeleton height={18} rounded width={18} />
          </>
        )}
      </span>
    </Link>
  );
}

