export const SEARCH_HEIGHT = 40;
export const SEARCH_GAP = 8;
export const MAP_HEIGHT = 56;
export const TIMELINE_PADDING = 8;
export const ROW_PADDING = 2;
export const ROW_HEIGHT = 24;
export const MARKER_HEIGHT = 24;
export const MARKER_NOTCH_HEIGHT = 8;

export const detectScrollbarWidth = (): number => {
  if (!('document' in globalThis)) return 0;
  const size = 400;
  const container = document.createElement('div');
  container.style.width = `${size}px`;
  container.style.height = `${size}px`;
  container.style.overflow = 'scroll';
  document.body.appendChild(container);
  const scrollbarWidth = size - container.scrollWidth;
  container.remove();

  return scrollbarWidth;
};

import { formatDuration } from '../lib/utils';

export { formatDuration };

export function getHighResInMs([seconds, nanoseconds]: [
  number,
  number,
]): number {
  return seconds * 1000 + nanoseconds / 1e6;
}

export function getMsInHighRes(ms: number): [number, number] {
  return [Math.floor(ms / 1000), (ms % 1000) * 1000];
}

/**
 * Formats a duration for timeline display (compact single-unit format).
 * @deprecated Use formatDuration(ms, true) instead.
 */
export const formatDurationForTimeline = (ms: number): string =>
  formatDuration(ms, true);

const timeSelectionFormatter = new Intl.NumberFormat(undefined, {
  minimumFractionDigits: 2,
  maximumFractionDigits: 2,
});

export function formatTimeSelection(ms: number): string {
  if (ms >= 1000) {
    return `${timeSelectionFormatter.format(ms / 1000)}s`;
  }
  return `${timeSelectionFormatter.format(ms)}ms`;
}

/**
 * Format an epoch-millisecond timestamp as a local wall-clock time.
 * Returns a compact HH:MM:SS.mmm string (24-hour format).
 */
export function formatWallClockTime(epochMs: number): string {
  const d = new Date(epochMs);
  const h = String(d.getHours()).padStart(2, '0');
  const m = String(d.getMinutes()).padStart(2, '0');
  const s = String(d.getSeconds()).padStart(2, '0');
  const ms = String(d.getMilliseconds()).padStart(3, '0');
  return `${h}:${m}:${s}.${ms}`;
}

import type {
  RootNode,
  Span,
  SpanNode,
  SpanNodeEvent,
  Trace,
  TraceNode,
  VisibleSpan,
} from '../types';
import { getHighResInMs, getMsInHighRes } from './timing';

export const parseTrace = (
  trace: Trace
): { root: RootNode; map: Record<string, SpanNode> } => {
  const { spans } = trace;
  const root: RootNode = {
    startTime: 0,
    endTime: 0,
    duration: 0,
    depth: 0,
    children: [],
  };
  const map: Record<string, SpanNode> = {};

  const resourceIndices = new Map<string, number>();
  const getResourceIndex = (resource: string): number => {
    const existing = resourceIndices.get(resource);
    if (existing) return existing;

    const index = resourceIndices.size + 1;
    resourceIndices.set(resource, index);
    return index;
  };

  let hasUserSpans = false;
  for (const span of spans) {
    const startTime = getHighResInMs(span.startTime);
    const endTime = getHighResInMs(span.endTime);
    const duration = getHighResInMs(span.duration);
    if (endTime > root.endTime) {
      root.endTime = endTime;
      root.duration = endTime - root.startTime;
    }
    if (root.startTime === 0 || startTime < root.startTime) {
      root.startTime = startTime;
      root.duration = root.endTime - startTime;
    }
    const isVercelResource = span.resource.startsWith('vercel.');
    if (!isVercelResource) {
      hasUserSpans = true;
    }

    const isVercel =
      isVercelResource &&
      (span.resource !== 'vercel.serverless-runtime' ||
        !('http.method' in span.attributes));

    const resourceIndex = isVercel ? 0 : getResourceIndex(span.resource);

    let label: string | undefined;
    if (isVercel) {
      label = `▲ ${span.name}`;
    } else if (span.label) {
      label = span.label;
    }
    map[span.spanId] = {
      parent: null as unknown as SpanNode,
      startTime,
      endTime,
      duration,
      span,
      depth: 0,
      label,
      events: parseEvents(span),
      isVercel,
      children: [],
      resourceIndex,
      // Pass through activeStartTime if present (for showing queued period)
      activeStartTime: span.activeStartTime
        ? getHighResInMs(span.activeStartTime)
        : undefined,
    };
  }

  const addTo = (node: SpanNode, parentId?: string): void => {
    let parent: TraceNode | undefined;
    if (parentId) {
      parent = map[parentId];
      if (!parent) {
        if (process.env.NODE_ENV === 'development') {
          console.warn('Could not find parent span with spanId: %s', parentId);
        }
        parent = root;
      }
    } else {
      parent = root;
    }
    node.parent = parent;
    parent.children.push(node);
  };

  const updateDepth = (node: TraceNode): void => {
    if ('parent' in node) {
      node.depth = node.parent.depth + 1;
    }
    for (const child of node.children) {
      updateDepth(child);
    }
  };

  let hintIdCounter = 1;
  const addInstrumentationHint = (node: TraceNode, name: string): boolean => {
    if ('parent' in node) {
      if (node.span.name === name) {
        let waitUntilStart = node.endTime;
        // Detect the parent that's most likely to be at the bottom of the UI
        const findParent = (span: SpanNode): SpanNode => {
          if (!span.children.length) {
            if (span.span.name === 'waitUntil') {
              waitUntilStart = span.startTime;
              return span.parent as SpanNode;
            }
            return span;
          }

          return (
            span.children
              .map(findParent)
              .sort((a, b) => a.duration - b.duration)[0] || span
          );
        };
        const parent = findParent(node);

        const spanId = `instrumentation-hint-${hintIdCounter++}`;
        const offset = node.duration * 0.05;
        const startTime = node.startTime + offset;
        const endTime = Math.max(
          startTime + offset,
          Math.min(waitUntilStart - node.duration * 0.01, node.endTime - offset)
        );
        const duration = endTime - startTime;
        const hint: SpanNode = {
          parent,
          startTime,
          endTime,
          duration,
          span: {
            spanId,
            name: 'Add your spans here',
            resource: '',
            kind: 0,
            library: {
              name: '',
            },
            status: {
              code: 200,
            },
            traceFlags: 0,
            attributes: {},
            links: [],
            events: [],
            startTime: getMsInHighRes(startTime),
            endTime: getMsInHighRes(endTime),
            duration: getMsInHighRes(duration),
          },
          depth: node.depth + 1,
          isVercel: false,
          isInstrumentationHint: true,
          children: [],
          resourceIndex: 1,
        };
        parent.children.push(hint);
        map[spanId] = hint;
        return true;
      }
    }
    for (const child of node.children) {
      if (addInstrumentationHint(child, name)) return true;
    }
    return false;
  };

  // Create tree by matching nodes to their parents
  for (const node of Object.values(map)) {
    addTo(node, node.span.parentSpanId);
  }

  // Adjust depth of each node now that the tree is fully constructed
  updateDepth(root);

  // Add hints in the places where user spans would appear
  if (!hasUserSpans) {
    for (const name of [
      'Invoke Function',
      'Invoke Middleware',
      'Vercel Runtime',
    ]) {
      if (addInstrumentationHint(root, name)) break;
    }
  }

  return { root, map };
};

const parseEvents = (span: Span): SpanNodeEvent[] | undefined => {
  if (!span.events.length) return;

  const keyPrefix = `${span.spanId}:ev`;

  return span.events
    .map<SpanNodeEvent>((event, index) => ({
      key: `${keyPrefix}${index}`,
      timestamp: getHighResInMs(event.timestamp),
      event,
    }))
    .sort((a, b) => a.timestamp - b.timestamp);
};

/**
 * Adds a node to a row and attempts to find the ideal placement
 * within an existing row, creating a new one if necessary
 */
export const addToRow = (
  placed: VisibleSpan[][],
  node: VisibleSpan,
  precision: number
): void => {
  const parent = node.parent as VisibleSpan | undefined;
  for (let y = (parent?.row || -1) + 1; ; ++y) {
    let row = placed[y];
    if (!row) {
      row = [];
      placed.push(row);
    } else if (
      !row.every(
        ({ startTime, endTime }) =>
          startTime + precision > node.endTime ||
          endTime - precision < node.startTime
      )
    ) {
      continue;
    }
    node.row = y;
    row.push(node);
    break;
  }
};

export const spanVisiblityHelper = (
  node: TraceNode,
  scale: number,
  visible: VisibleSpan[]
): void => {
  if ('parent' in node) {
    const n = node as VisibleSpan;
    n.row = -1;
    // Always make spans visible regardless of width
    n.isVisible = true;
    n.isHovered = false;
    if (!n.isVisible) return;

    visible.push(n);
  }

  for (const child of node.children) {
    spanVisiblityHelper(child, scale, visible);
  }
};

export const adjustSpanVisibility = (
  span: VisibleSpan,
  _scale: number
): boolean => {
  // Always make spans visible regardless of width
  span.isVisible = true;
  span.isHovered = false;

  return span.isVisible;
};

'use client';

import type { CSSProperties, MutableRefObject } from 'react';
import { useCallback, useRef } from 'react';

type SetStyle = (propertyName: string, value: string | undefined) => void;

interface ImmediateStyle {
  setStyle: SetStyle;
  styleRef: MutableRefObject<CSSProperties>;
  style: CSSProperties;
}

/**
 * Update an element's style without forcing renders, but in a way that is still
 * safe if the element re-renders for another reason.
 * @returns The current style & a method to update the style
 */
export function useImmediateStyle(
  ref: MutableRefObject<HTMLElement | null>
): ImmediateStyle {
  const styleRef = useRef<CSSProperties>({});
  const setStyle = useCallback<SetStyle>(
    (propertyName, value) => {
      // @ts-expect-error typeof keyof CSSProperties is too big of a union
      styleRef.current[propertyName] = value;
      if (!ref.current) return;
      if (!value) {
        ref.current.style.removeProperty(propertyName);
        return;
      }
      ref.current.style.setProperty(propertyName, value);
    },
    [ref]
  );

  return { setStyle, styleRef, style: { ...styleRef.current } };
}

'use client';

import { useEffect, useRef, useState } from 'react';
import { useTraceViewer } from '../context';
import type {
  VisibleSpan,
  VisibleSpanEvent,
  WorkerRequest,
  WorkerResponse,
} from '../types';
import {
  MARKER_HEIGHT,
  ROW_HEIGHT,
  ROW_PADDING,
  TIMELINE_PADDING,
} from './constants';
import { adjustSpanVisibility } from './tree';

type UpdateFilter = (filter: string) => void;

interface QueuedSpan {
  /** The distance from this span to the viewport */
  d: number;
  /** The span that's waiting to be rendered */
  span: VisibleSpan;
}

function emptyArrayInit<T>(): T[] {
  return [];
}

export const useStreamingSpans = (
  highlightedSpans?: string[],
  eagerRender = false
): {
  rows: VisibleSpan[][];
  spans: VisibleSpan[];
  events: VisibleSpanEvent[];
  scale: number;
} => {
  const { state, dispatch } = useTraceViewer();
  const {
    root,
    filter: ctxFilter,
    scale,
    timelineRef,
    timelineWidth,
    spanMap,
    scrollSnapshotRef,
    selected,
    memoCacheRef,
  } = state;
  const timelineHeight = useStableValue(state.timelineHeight);
  const counterRef = useRef(0);
  const [rows, setRows] = useState<VisibleSpan[][]>(emptyArrayInit);
  const [visibleSpans, setVisibleSpans] =
    useState<VisibleSpan[]>(emptyArrayInit);
  const [visibleEvents, setVisibleEvents] =
    useState<VisibleSpanEvent[]>(emptyArrayInit);
  const [resultScale, setResultScale] = useState(-1);

  const updateFilterRef = useRef<UpdateFilter>(undefined);
  useEffect(() => updateFilterRef.current?.(ctxFilter), [ctxFilter]);

  useEffect(() => {
    if (!highlightedSpans?.length) return;

    for (const row of rows) {
      for (const node of row) {
        const isHighlighted = highlightedSpans.includes(node.span.spanId);
        if (node.isHighlighted === isHighlighted) continue;
        node.isHighlighted = isHighlighted;
        memoCacheRef.current.set(node.span.spanId, {});
      }
    }
    dispatch({
      type: 'forceRender',
    });
  }, [rows, highlightedSpans, dispatch, memoCacheRef]);

  useEffect(() => {
    if (!root.startTime) return;

    const worker = new Worker(new URL('../worker', import.meta.url), {
      type: 'module',
    });
    let requestId = ++counterRef.current;
    const onMessage = (event: MessageEvent): void => {
      const data = event.data as WorkerResponse;

      switch (data.type) {
        case 'setRowsResult': {
          if (data?.requestId !== requestId) return;
          if (data.isEnd) {
            for (const row of data.rows) {
              for (const node of row) {
                // Ensure that we remap to the original span to reduce memory overhead
                // and confusion down the line
                node.span = spanMap[node.span.spanId]?.span ?? node.span;
              }
            }
          }
          setRows(data.rows);
          break;
        }
        case 'updateHighlight': {
          if (data?.requestId !== requestId) return;
          const { matches } = data;
          setRows((previous) => {
            for (const row of previous) {
              for (const node of row) {
                const isHighlighted = matches.has(node.span.spanId);
                if (node.isHighlighted === isHighlighted) continue;
                node.isHighlighted = isHighlighted;
                memoCacheRef.current.set(node.span.spanId, {});
              }
            }
            return previous;
          });
          dispatch({
            type: 'forceRender',
          });
          break;
        }
        default:
          break;
      }
    };
    worker.addEventListener('message', onMessage);

    const message: WorkerRequest = {
      requestId,
      type: 'calculateSpanPositions',
      root,
    };
    worker.postMessage(message);

    updateFilterRef.current = (_filter) => {
      const filter = _filter.trim().toLocaleLowerCase();
      if (!filter) {
        setRows((previous) =>
          previous.map((row) =>
            row.map((node) => {
              node.isHighlighted = undefined;
              return {
                ...node,
              };
            })
          )
        );
        return;
      }

      requestId = ++counterRef.current;
      const filterMessage: WorkerRequest = {
        type: 'filterSpans',
        requestId,
        root,
        filter,
      };
      worker.postMessage(filterMessage);
    };

    return () => {
      worker.terminate();
    };
  }, [root, spanMap, dispatch, memoCacheRef]);

  useEffect(() => {
    if (!rows.length) return;

    if (eagerRender) {
      const visible: VisibleSpan[] = [];
      const events: VisibleSpanEvent[] = [];
      for (const row of rows) {
        for (const span of row) {
          if (!adjustSpanVisibility(span, scale)) continue;
          visible.push(span);
          if (span.events) {
            events.push(...span.events);
          }
        }
      }
      setVisibleSpans(visible);
      setVisibleEvents(events);
      setResultScale(scale);
      return;
    }

    const $timeline = timelineRef.current;
    let snapshot = scrollSnapshotRef.current;
    let hasScrolled = false;
    let isDone = false;
    let maxD = 0;
    let currentD = 0;
    const overscan = Math.max(500, timelineWidth * 0.5);
    const queue = new Array<QueuedSpan[] | null>(rows.length).fill(null);

    const buildQueue = (): void => {
      isDone = true;

      const lastRow = Math.min(
        1 + currentD + Math.ceil(snapshot?.endRow ?? Number.POSITIVE_INFINITY),
        rows.length
      );
      for (let i = lastRow; i--; ) {
        if (queue[i]) continue;
        const rowDelta = getRowDelta(i);
        if (Math.abs(rowDelta) > currentD) {
          isDone = false;
          if (rowDelta > 0) {
            continue;
          } else {
            break;
          }
        }

        const queueRow: QueuedSpan[] = [];
        const row = rows[i];
        if (!row) continue;

        for (const span of row) {
          if (!adjustSpanVisibility(span, scale)) continue;

          const d = getDistance(span);
          maxD = Math.max(d, maxD);

          queueRow.push({
            d,
            span,
          });
        }

        queue[i] = queueRow;
      }
    };

    /**
     * This returns the signed distance between the row and the targeted rows
     */
    const getRowDelta = (row: number): number => {
      if (!snapshot) return 0;

      if (row < snapshot.startRow) {
        return row - snapshot.startRow;
      } else if (row > snapshot.endRow) {
        return row - snapshot.endRow;
      }

      return 0;
    };

    const getDistance = (span: VisibleSpan): number => {
      if (!snapshot) return 0;

      let xDistance = 0;
      if (span.endTime < snapshot.startTime) {
        xDistance = snapshot.startTime - span.endTime;
      } else if (span.startTime > snapshot.endTime) {
        xDistance = span.startTime - snapshot.endTime;
      }

      const yDistance = Math.abs(getRowDelta(span.row));

      if (!xDistance && !yDistance) return 0;

      return Math.sqrt(
        (xDistance / scale) ** 2 + (yDistance * ROW_HEIGHT + ROW_PADDING) ** 2
      );
    };

    const updateSnapshot = (): void => {
      if (!$timeline) return;

      const { scrollLeft, scrollTop } = $timeline;
      const anchorX = 0;
      const anchorT = scrollLeft / scale;
      const startRow =
        (scrollTop - MARKER_HEIGHT - TIMELINE_PADDING) /
        (ROW_HEIGHT + ROW_PADDING);
      const endRow =
        startRow + Math.ceil(timelineHeight / (ROW_HEIGHT + ROW_PADDING));

      snapshot = {
        anchorT,
        anchorX,
        scrollLeft,
        scrollTop,
        startTime: root.startTime + scrollLeft / scale,
        endTime: root.startTime + (scrollLeft + timelineWidth) / scale,
        startRow,
        endRow,
        scale,
      };
      scrollSnapshotRef.current = snapshot;

      for (let i = queue.length; i--; ) {
        queue[i] = null;
      }
    };

    let nextFrame = 0;
    const onFrame = (): void => {
      if (hasScrolled || !snapshot) {
        hasScrolled = false;
        updateSnapshot();
      }
      buildQueue();
      const visible: VisibleSpan[] = [];
      const events: VisibleSpanEvent[] = [];
      for (const row of queue) {
        if (!row) continue;

        for (const { d, span } of row) {
          if (d > currentD) continue;
          visible.push(span);
          if (span.events) {
            events.push(...span.events);
          }
        }
      }

      if (currentD < overscan && (!isDone || currentD < maxD)) {
        currentD = Math.min(overscan, currentD + 100);
        nextFrame = requestAnimationFrame(onFrame);
      }

      setVisibleSpans(visible);
      setVisibleEvents(events);
      setResultScale(scale);
    };
    onFrame();

    let ignoreT = Date.now();
    const onWheel = (event: WheelEvent): void => {
      if (event.ctrlKey || event.metaKey) {
        ignoreT = Date.now();
      }
    };
    $timeline?.addEventListener('wheel', onWheel);

    const onScroll = (): void => {
      if (Date.now() - ignoreT <= 50) return;

      hasScrolled = true;
      cancelAnimationFrame(nextFrame);
      nextFrame = requestAnimationFrame(onFrame);
    };
    $timeline?.addEventListener('scroll', onScroll);

    return () => {
      cancelAnimationFrame(nextFrame);
      $timeline?.removeEventListener('wheel', onWheel);
      $timeline?.removeEventListener('scroll', onScroll);
    };
  }, [
    rows,
    root,
    scale,
    scrollSnapshotRef,
    timelineRef,
    timelineWidth,
    timelineHeight,
    eagerRender,
  ]);

  useEffect(() => {
    if (!selected) return;

    let span: VisibleSpan | undefined;
    for (const x of visibleSpans) {
      if (x.span.spanId === selected.span.spanId) {
        span = x;
        break;
      }
    }

    const $span = span?.ref?.current;
    if (!span || !$span) return;

    span.isSelected = true;
    $span.setAttribute('data-selected', '');

    return () => {
      span.isSelected = false;
      $span.removeAttribute('data-selected');
    };
  }, [visibleSpans, selected]);

  return {
    rows,
    spans: visibleSpans,
    events: visibleEvents,
    scale: resultScale,
  };
};

/**
 * This hook keeps returning the same value until the current value
 * has been stable for a few frames in a row
 */
function useStableValue<T>(value: T): T {
  const [cached, setCached] = useState(value);

  useEffect(() => {
    if (cached === value) return;

    let frameCount = 0;
    let nextFrame = 0;
    const onFrame = (): void => {
      if (++frameCount <= 3) {
        nextFrame = requestAnimationFrame(onFrame);
        return;
      }

      setCached(value);
    };
    onFrame();

    return () => {
      cancelAnimationFrame(nextFrame);
    };
  }, [cached, value]);

  return cached;
}

'use client';

import { useEffect, useRef } from 'react';

/**
 * The delta is positive while zooming in, negative while zooming out
 */
export type TrackpadZoomHandler = (delta: number) => void;

export function useTrackpadZoom(handler: TrackpadZoomHandler): void {
  const handlerRef = useRef(handler);
  handlerRef.current = handler;

  useEffect(() => {
    let pendingDelta = 0;
    let nextFrame = 0;
    const onFrame = (): void => {
      handlerRef.current(pendingDelta);
      pendingDelta = 0;
    };

    const onWheel = (event: WheelEvent): void => {
      if (!event.ctrlKey && !event.metaKey) return;

      event.preventDefault();
      let delta = -event.deltaY;

      switch (event.deltaMode) {
        case WheelEvent.DOM_DELTA_PAGE:
          delta *= window.innerHeight;
          break;
        case WheelEvent.DOM_DELTA_LINE:
          delta *= 20;
          break;
        default:
          break;
      }

      pendingDelta += delta;
      cancelAnimationFrame(nextFrame);
      nextFrame = requestAnimationFrame(onFrame);
    };

    window.addEventListener('wheel', onWheel, { passive: false });

    return () => {
      window.removeEventListener('wheel', onWheel);
      cancelAnimationFrame(nextFrame);
    };
  }, []);
}
